    def _ensure_integration_indexes(self, conn: sqlite3.Connection) -> None:
        try:
            conn.execute(
                """
                CREATE UNIQUE INDEX IF NOT EXISTS idx_medis_external_result_id_unique
                    ON medis_investigations(external_result_id)
                    WHERE external_result_id != ''
                """
            )
        except sqlite3.Error:
            # Indexul nu trebuie sa blocheze pornirea pe baze vechi/inconsistente.
            pass

