    def get_api_idempotency(self, *, endpoint: str, key: str) -> Optional[Dict[str, Any]]:
        ep = (endpoint or "").strip()
        idem = (key or "").strip()
        if not ep or not idem:
            return None
        with self._connect() as conn:
            row = conn.execute(
                """
                SELECT id, endpoint, idem_key, request_hash, response_status, response_json,
                       created_by_user_id, created_at, updated_at
                FROM api_idempotency_keys
                WHERE endpoint = ? AND idem_key = ?
                LIMIT 1
                """,
                (ep, idem),
            ).fetchone()
            if not row:
                return None
            return dict(row)

    def save_api_idempotency(
        self,
        *,
        endpoint: str,
        key: str,
        request_hash: str,
        response_status: int,
        response_json: str,
        user_id: Optional[int],
    ) -> None:
        ep = (endpoint or "").strip()
        idem = (key or "").strip()
        req_hash = (request_hash or "").strip()
        if not ep or not idem:
            raise ValueError("Endpoint/Idempotency-Key lipsa.")
        ts = now_ts()
        with self._connect() as conn:
            conn.execute(
                """
                INSERT INTO api_idempotency_keys (
                    endpoint, idem_key, request_hash, response_status,
                    response_json, created_by_user_id, created_at, updated_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(endpoint, idem_key) DO UPDATE SET
                    request_hash = excluded.request_hash,
                    response_status = excluded.response_status,
                    response_json = excluded.response_json,
                    created_by_user_id = excluded.created_by_user_id,
                    updated_at = excluded.updated_at
                """,
                (
                    ep,
                    idem,
                    req_hash,
                    int(response_status or 200),
                    (response_json or "").strip(),
                    int(user_id) if user_id else None,
                    ts,
                    ts,
                ),
            )
            conn.commit()

    def list_integration_queue_jobs(self, *, limit: int = 200, status: str = "") -> List[sqlite3.Row]:
        lim = max(1, int(limit or 200))
        status_filter = (status or "").strip().lower()
        with self._connect() as conn:
            if status_filter:
                return conn.execute(
                    """
                    SELECT id, provider, operation, entity_type, entity_id, status, attempt_count,
                           next_retry_at, last_error, last_http_code, updated_at
                    FROM integration_outbox
                    WHERE status = ?
                    ORDER BY updated_at DESC, id DESC
                    LIMIT ?
                    """,
                    (status_filter, lim),
                ).fetchall()
            return conn.execute(
                """
                SELECT id, provider, operation, entity_type, entity_id, status, attempt_count,
                       next_retry_at, last_error, last_http_code, updated_at
                FROM integration_outbox
                ORDER BY updated_at DESC, id DESC
                LIMIT ?
                """,
                (lim,),
            ).fetchall()

    def run_startup_self_check(self) -> Dict[str, Any]:
        required_tables = (
            "patients",
            "admissions",
            "institutional_reports",
            "medis_investigations",
            "integration_outbox",
            "shadow_write_journal",
            "diagnosis_suggestions_log",
            "drg_icm_simulations",
            "api_idempotency_keys",
            "job_executions",
            "integration_dry_run_logs",
            "user_sessions",
            "patient_record_snapshots",
        )
        result: Dict[str, Any] = {
            "db_access": False,
            "required_tables_ok": False,
            "missing_tables": [],
            "integration_queue_pending": 0,
            "integration_queue_retry": 0,
            "shadow_sync_pending": 0,
            "shadow_sync_failed": 0,
            "checked_at": now_ts(),
        }
        try:
            with self._connect() as conn:
                result["db_access"] = True
                table_rows = conn.execute(
                    "SELECT name FROM sqlite_master WHERE type='table'"
                ).fetchall()
                table_names = {str(row[0]).strip().lower() for row in table_rows}
                missing = [name for name in required_tables if name not in table_names]
                result["missing_tables"] = missing
                result["required_tables_ok"] = len(missing) == 0
                pending_row = conn.execute(
                    "SELECT COUNT(*) AS c FROM integration_outbox WHERE status = 'pending'"
                ).fetchone()
                retry_row = conn.execute(
                    "SELECT COUNT(*) AS c FROM integration_outbox WHERE status = 'retry'"
                ).fetchone()
                result["integration_queue_pending"] = int((pending_row["c"] if pending_row else 0) or 0)
                result["integration_queue_retry"] = int((retry_row["c"] if retry_row else 0) or 0)
                shadow_pending = conn.execute(
                    "SELECT COUNT(*) AS c FROM shadow_write_journal WHERE status = 'pending'"
                ).fetchone()
                shadow_failed = conn.execute(
                    "SELECT COUNT(*) AS c FROM shadow_write_journal WHERE status = 'failed'"
                ).fetchone()
                result["shadow_sync_pending"] = int((shadow_pending["c"] if shadow_pending else 0) or 0)
                result["shadow_sync_failed"] = int((shadow_failed["c"] if shadow_failed else 0) or 0)
        except Exception as exc:
            result["error"] = str(exc)
        return result

    def record_job_execution(
        self,
        *,
        job_name: str,
        status: str,
        duration_ms: int,
        details_json: str,
        correlation_id: str = "",
    ) -> int:
        name = (job_name or "").strip()
        if not name:
            raise ValueError("job_name este obligatoriu.")
        state = (status or "").strip().lower() or "ok"
        if state not in {"ok", "warning", "error"}:
            state = "ok"
        with self._connect() as conn:
            cur = conn.execute(
                """
                INSERT INTO job_executions (
                    job_name, status, duration_ms, details_json, correlation_id, created_at
                ) VALUES (?, ?, ?, ?, ?, ?)
                """,
                (
                    name,
                    state,
                    max(0, int(duration_ms or 0)),
                    (details_json or "").strip(),
                    (correlation_id or "").strip(),
                    now_ts(),
                ),
            )
            conn.commit()
            return int(cur.lastrowid)

