    def enqueue_shadow_write_event(
        self,
        *,
        action_key: str,
        source: str,
        payload_json: str,
        payload_hash: str = "",
    ) -> int:
        action = (action_key or "").strip()
        if not action:
            raise ValueError("action_key shadow lipsa.")
        payload_text = (payload_json or "").strip()
        hash_value = (payload_hash or "").strip()
        if not hash_value:
            hash_value = hashlib.sha256(payload_text.encode("utf-8")).hexdigest()
        ts = now_ts()
        with self._connect() as conn:
            cur = conn.execute(
                """
                INSERT INTO shadow_write_journal (
                    action_key, source, payload_json, payload_hash, status, retry_count,
                    next_retry_at, last_error, last_attempt_at, created_at, updated_at
                ) VALUES (?, ?, ?, ?, 'pending', 0, ?, '', '', ?, ?)
                """,
                (
                    action,
                    (source or "").strip() or "api",
                    payload_text,
                    hash_value,
                    ts,
                    ts,
                    ts,
                ),
            )
            conn.commit()
            return int(cur.lastrowid)

    def _compute_shadow_next_retry_ts(self, retry_count: int, base_seconds: float = 1.0) -> str:
        delay = max(1.0, float(base_seconds)) * (2 ** max(0, int(retry_count) - 1))
        delay = min(3600.0, delay)
        return (datetime.now() + timedelta(seconds=delay)).strftime("%Y-%m-%d %H:%M:%S")

    def claim_due_shadow_writes(self, *, max_jobs: int = 100) -> List[sqlite3.Row]:
        lim = max(1, int(max_jobs or 100))
        now = now_ts()
        with self._connect() as conn:
            return conn.execute(
                """
                SELECT id, action_key, source, payload_json, payload_hash, status,
                       retry_count, next_retry_at, last_error, last_attempt_at, created_at, updated_at
                FROM shadow_write_journal
                WHERE status = 'pending' AND next_retry_at <= ?
                ORDER BY next_retry_at ASC, id ASC
                LIMIT ?
                """,
                (now, lim),
            ).fetchall()

    def mark_shadow_write_synced(self, *, journal_id: int) -> None:
        ts = now_ts()
        with self._connect() as conn:
            conn.execute(
                """
                UPDATE shadow_write_journal
                SET status = 'synced',
                    last_error = '',
                    last_attempt_at = ?,
                    updated_at = ?
                WHERE id = ?
                """,
                (ts, ts, int(journal_id)),
            )
            conn.commit()

    def mark_shadow_write_retry(
        self,
        *,
        journal_id: int,
        retry_count: int,
        error: str,
        base_seconds: float = 1.0,
    ) -> None:
        next_retry = self._compute_shadow_next_retry_ts(retry_count, base_seconds=base_seconds)
        ts = now_ts()
        with self._connect() as conn:
            conn.execute(
                """
                UPDATE shadow_write_journal
                SET status = 'pending',
                    retry_count = ?,
                    next_retry_at = ?,
                    last_error = ?,
                    last_attempt_at = ?,
                    updated_at = ?
                WHERE id = ?
                """,
                (
                    max(0, int(retry_count or 0)),
                    next_retry,
                    (error or "").strip(),
                    ts,
                    ts,
                    int(journal_id),
                ),
            )
            conn.commit()

