    def mark_institutional_report_submitted(
        self,
        *,
        report_id: int,
        external_reference: str,
        ack_payload: str,
        user_id: Optional[int] = None,
    ) -> None:
        _ = user_id
        ext_ref = (external_reference or "").strip()
        if not ext_ref:
            raise ValueError("Referinta externa este obligatorie pentru raport marcat ca transmis.")
        with self._connect() as conn:
            row = conn.execute(
                "SELECT id, validation_errors FROM institutional_reports WHERE id = ? LIMIT 1",
                (report_id,),
            ).fetchone()
            if not row:
                raise ValueError("Raport institutional inexistent.")
            if (row["validation_errors"] or "").strip():
                raise ValueError("Raportul are erori de validare si nu poate fi marcat transmis.")
            conn.execute(
                """
                UPDATE institutional_reports
                SET status = 'submitted',
                    external_reference = ?,
                    ack_payload = ?,
                    submitted_at = ?,
                    transport_state = CASE
                        WHEN transport_state = '' THEN 'submitted_local'
                        ELSE transport_state
                    END,
                    transport_attempts = CASE
                        WHEN transport_attempts < 1 THEN 1
                        ELSE transport_attempts
                    END,
                    transport_last_error = '',
                    updated_at = ?
                WHERE id = ?
                """,
                (
                    ext_ref,
                    (ack_payload or "").strip(),
                    now_ts(),
                    now_ts(),
                    report_id,
                ),
            )
            conn.commit()

    def has_submitted_institutional_report(self, admission_id: int, report_type: str) -> bool:
        kind = (report_type or "").strip().lower()
        if kind not in {"siui", "drg"}:
            return False
        with self._connect() as conn:
            row = conn.execute(
                """
                SELECT 1
                FROM institutional_reports
                WHERE admission_id = ?
                  AND report_type = ?
                  AND status = 'submitted'
                LIMIT 1
                """,
                (admission_id, kind),
            ).fetchone()
        return row is not None

    def add_order(
        self,
        patient_id: int,
        admission_id: Optional[int],
        order_type: str,
        priority: str,
        order_text: str,
        user_id: Optional[int],
    ) -> int:
        normalized_admission_id: Optional[int]
        raw_admission_id: Any = admission_id
        if isinstance(raw_admission_id, (tuple, list)):
            raw_admission_id = raw_admission_id[0] if raw_admission_id else None
        try:
            normalized_admission_id = int(raw_admission_id) if raw_admission_id is not None else None
        except Exception:
            normalized_admission_id = None

        with self._connect() as conn:
            cur = conn.execute(
                """
                INSERT INTO orders_medical (
                    patient_id, admission_id, order_type, priority, order_text,
                    status, ordered_at, ordered_by_user_id
                ) VALUES (?, ?, ?, ?, ?, 'ordered', ?, ?)
                """,
                (
                    patient_id,
                    normalized_admission_id,
                    order_type.strip(),
                    priority.strip(),
                    order_text.strip(),
                    now_ts(),
                    user_id,
                ),
            )
            conn.commit()
            return int(cur.lastrowid)

