    def _configure_observability_runtime(self) -> None:
        self.observability_runtime_active = configure_telemetry(
            service_name=(self.observability_service_name or "").strip() or "pacienti-ai-desktop",
            enabled=bool(self.observability_enabled),
            otlp_endpoint=(self.observability_otlp_endpoint or "").strip(),
            sample_ratio=float(self.observability_sample_ratio or 1.0),
        )
        self.enterprise_logger.info(
            "observability runtime configured: enabled=%s active=%s telemetry=%s",
            bool(self.observability_enabled),
            bool(self.observability_runtime_active),
            bool(telemetry_enabled()),
        )

    def _integration_live_ready(self, provider: str) -> bool:
        prov = (provider or "").strip().lower()
        if prov == "siui_drg":
            return bool(
                self.siui_drg_live_enabled
                and self.siui_drg_base_url
                and self.siui_drg_endpoint_siui_submit
                and self.siui_drg_endpoint_drg_submit
            )
        if prov == "medis":
            return bool(
                self.medis_live_enabled
                and self.medis_base_url
                and self.medis_endpoint_order_submit
            )
        return False

    def _ai_role_allowed(self) -> bool:
        role = normalize_role(self.current_user.get("role", ""))
        if role == "admin":
            return True
        if not self.ai_allowed_roles:
            return True
        return role in set(self.ai_allowed_roles)

    def _build_ui(self) -> None:
        top = ttk.Frame(self.root)
        top.pack(fill="x", padx=8, pady=(8, 0))
        role_label = self.current_user.get("role", "")
        user_label = self.current_user.get("display_name", self.current_user.get("username", ""))
        ttk.Label(
            top,
            text=f"{DEFAULT_HOSPITAL_NAME} | Utilizator: {user_label} ({role_label})",
            font=("Segoe UI", 10, "bold"),
        ).pack(side=LEFT)
        right_tools = ttk.Frame(top)
        right_tools.pack(side=RIGHT)
        self._init_ui_compact_toolbar_styles()
        self.guardrail_var = tk.StringVar(value="Mod spital activ: audit + fluxuri internare")
        ttk.Label(right_tools, textvariable=self.guardrail_var, foreground="#1d4ed8").pack(side=LEFT, padx=(0, 10))
        self.alert_status_var = tk.StringVar(value="Alerte critice: monitorizare activa")
        self.alert_status_label = tk.Label(right_tools, textvariable=self.alert_status_var, fg="#b91c1c")
        self.alert_status_label.pack(side=LEFT, padx=(0, 10))
        self.ui_compact_status_var = tk.StringVar()
        self.ui_compact_status_button = None
        self.ui_compact_status_label = None
        self._refresh_ui_compact_toolbar_status()
        if self._has_role("admin"):
            self.ui_compact_status_button = ttk.Button(
                right_tools,
                textvariable=self.ui_compact_status_var,
                command=self.toggle_ui_compact_from_toolbar,
                style="UICompactOff.TButton",
            )
            self.ui_compact_status_button.pack(side=LEFT, padx=(0, 10))
        else:
            self.ui_compact_status_label = ttk.Label(
                right_tools,
                textvariable=self.ui_compact_status_var,
                style="UICompactOff.TLabel",
            )
            self.ui_compact_status_label.pack(
                side=LEFT, padx=(0, 10)
            )
        self._refresh_ui_compact_toolbar_status()
        ttk.Button(right_tools, text="Muta alerte 5m", command=self.mute_alerts_5m).pack(side=LEFT, padx=(0, 10))
        ttk.Button(right_tools, text="Test notificari", command=self.test_external_notifications).pack(
            side=LEFT, padx=(0, 10)
        )
        ttk.Button(right_tools, text="Backup acum", command=self.create_manual_backup).pack(side=LEFT, padx=(0, 10))
        ttk.Button(right_tools, text="Restore backup", command=self.restore_backup_dialog).pack(side=LEFT, padx=(0, 10))
        ttk.Button(right_tools, text="Schimba parola", command=self.change_my_password).pack(side=LEFT)
        if self._has_role("admin"):
            ttk.Button(right_tools, text="Setari UI", command=self.open_ui_settings_tab).pack(side=LEFT, padx=(10, 0))
        self._group_actions_into_menus(
            parent=right_tools,
            context_key="toolbar_operatiuni_sistem",
            menu_specs=[
                {
                    "menu_label": "Operatiuni sistem",
                    "pack_padx": (0, 10),
                    "entries": [
                        {"label": "Muta alerte 5m"},
                        {"label": "Test notificari"},
                        {"label": "Backup acum"},
                        {"label": "Restore backup"},
                    ],
                }
            ],
        )

        main = ttk.PanedWindow(self.root, orient=tk.HORIZONTAL)
        main.pack(fill=BOTH, expand=True, padx=8, pady=8)

        left = ttk.Frame(main, width=350)
        right = ttk.Frame(main)
        main.add(left, weight=1)
        main.add(right, weight=3)

        self._build_patients_panel(left)
        self._build_right_panel(right)

    def _init_ui_compact_toolbar_styles(self) -> None:
        if bool(getattr(self, "_ui_compact_toolbar_styles_initialized", False)):
            return
        style = ttk.Style(self.root)
        on_fg = "#166534"
        off_fg = "#6b7280"
        try:
            style.configure("UICompactOn.TButton", foreground=on_fg)
            style.map(
                "UICompactOn.TButton",
                foreground=[("active", on_fg), ("pressed", on_fg), ("!disabled", on_fg)],
            )
        except Exception:
            pass
        try:
            style.configure("UICompactOff.TButton", foreground=off_fg)
            style.map(
                "UICompactOff.TButton",
                foreground=[("active", off_fg), ("pressed", off_fg), ("!disabled", off_fg)],
            )
        except Exception:
            pass
        try:
            style.configure("UICompactOn.TLabel", foreground=on_fg)
            style.configure("UICompactOff.TLabel", foreground=off_fg)
        except Exception:
            pass
        self._ui_compact_toolbar_styles_initialized = True

    def _refresh_ui_compact_toolbar_status(self) -> None:
        if not hasattr(self, "ui_compact_status_var"):
            return
        enabled = bool(getattr(self, "ui_compact_menus_enabled", True))
        self.ui_compact_status_var.set(f"UI compact: {'ON' if enabled else 'OFF'}")
        if self.ui_compact_status_button is not None:
            try:
                self.ui_compact_status_button.configure(
                    style="UICompactOn.TButton" if enabled else "UICompactOff.TButton"
                )
            except Exception:
                pass
        if self.ui_compact_status_label is not None:
            try:
                self.ui_compact_status_label.configure(
                    style="UICompactOn.TLabel" if enabled else "UICompactOff.TLabel"
                )
            except Exception:
                pass

    def toggle_ui_compact_from_toolbar(self) -> None:
        if not self._require_role("Toggle UI compact", "admin"):
            return
        current = bool(getattr(self, "ui_compact_menus_enabled", True))
        target = not current
        decision = messagebox.askyesno(
            "UI compact menus",
            (
                f"Schimbi UI compact pe {'ON' if target else 'OFF'}?\n\n"
                "Setarea se salveaza imediat. Efectul complet se aplica dupa restart."
            ),
        )
        if not decision:
            return
        self.ui_compact_menus_enabled = target
        try:
            self.db.set_setting("UI_COMPACT_MENUS_ENABLED", "1" if target else "0")
        except Exception as exc:
            messagebox.showerror("UI compact menus", f"Nu am putut salva setarea.\n{exc}")
            return
        self._refresh_ui_compact_toolbar_status()
        if hasattr(self, "settings_bool_vars") and "UI_COMPACT_MENUS_ENABLED" in self.settings_bool_vars:
            self.settings_bool_vars["UI_COMPACT_MENUS_ENABLED"].set(target)
        if hasattr(self, "settings_hint_var"):
            self.settings_hint_var.set(
                f"UI compact menus: {'ON' if target else 'OFF'}. Restart necesar pentru aplicare completa."
            )
        self._audit(
            "toggle_ui_compact_menus_toolbar",
            self._audit_details_from_pairs(("value", "1" if target else "0")),
        )
        messagebox.showinfo(
            "UI compact menus",
            (
                f"Setarea a fost salvata: {'ON' if target else 'OFF'}.\n"
                "Reporneste aplicatia pentru a vedea modificarea in toate tab-urile."
            ),
        )

    @staticmethod
    def _normalize_action_label(label: str) -> str:
        return re.sub(r"\s+", " ", str(label or "").strip()).lower()

    @staticmethod
    def _action_key_slug(value: str) -> str:
        return re.sub(r"[^a-z0-9]+", "_", str(value or "").strip().lower()).strip("_") or "action"

    def _unique_action_key(self, context_key: str, label: str) -> str:
        base = f"{self._action_key_slug(context_key)}:{self._action_key_slug(label)}"
        count = int(self.menu_action_key_counter.get(base, 0))
        self.menu_action_key_counter[base] = count + 1
        if count <= 0:
            return base
        return f"{base}_{count + 1}"

    def _action_key_from_context_label(self, context_key: str, label: str) -> str:
        return f"{self._action_key_slug(context_key)}:{self._action_key_slug(label)}"

    def _remember_menu_action_label(self, label: str, action_key: str) -> None:
        norm = self._normalize_action_label(label)
        if not norm:
            return
        bucket = self.menu_action_keys_by_label.setdefault(norm, [])
        if action_key not in bucket:
            bucket.append(action_key)

    def _register_menu_action(self, action_key: str, menu_ref: tk.Menu, index: int) -> None:
        bucket = self.menu_action_registry.setdefault(action_key, [])
        bucket.append((menu_ref, int(index)))

    def _set_action_enabled(self, action_key: str, enabled: bool) -> None:
        state = "normal" if enabled else "disabled"
        for menu_ref, index in self.menu_action_registry.get(action_key, []):
            try:
                menu_ref.entryconfigure(index, state=state)
            except Exception:
                pass

    def _set_action_enabled_by_label(self, label: str, enabled: bool) -> None:
        norm = self._normalize_action_label(label)
        for action_key in self.menu_action_keys_by_label.get(norm, []):
            self._set_action_enabled(action_key, enabled)

    @staticmethod
    def _safe_add_separator(menu: tk.Menu) -> None:
        try:
            end_index = menu.index("end")
        except Exception:
            end_index = None
        if end_index is None:
            return
        try:
            last_kind = str(menu.type(end_index) or "")
        except Exception:
            last_kind = ""
        if last_kind != "separator":
            menu.add_separator()

    def _post_menubutton_menu(self, menubutton: ttk.Menubutton) -> None:
        menu: Optional[tk.Menu] = None
        try:
            menu_name = str(menubutton.cget("menu") or "").strip()
            if not menu_name:
                return
            menu = menubutton.nametowidget(menu_name)
            x = int(menubutton.winfo_rootx())
            y = int(menubutton.winfo_rooty() + menubutton.winfo_height())
            menu.tk_popup(x, y)
            try:
                if menu.index("end") is not None:
                    menu.activate(0)
                    menu.focus_set()
            except Exception:
                pass
        except Exception:
            return
        finally:
            try:
                if menu is not None:
                    menu.grab_release()
            except Exception:
                pass

    def _on_menubutton_key_open(self, menubutton: ttk.Menubutton) -> str:
        self._post_menubutton_menu(menubutton)
        return "break"

    def _bind_menubutton_keyboard(self, menubutton: ttk.Menubutton) -> None:
        for sequence in ("<Return>", "<KP_Enter>", "<space>", "<Down>", "<Alt-Down>"):
            menubutton.bind(
                sequence,
                lambda _event, m=menubutton: self._on_menubutton_key_open(m),
            )

    def _add_menu_items(self, menu: tk.Menu, node: Dict[str, Any]) -> None:
        for group_name, group_node in node.get("groups", {}).items():
            submenu = tk.Menu(menu, tearoff=False)
            menu.add_cascade(label=group_name, menu=submenu)
            self._add_menu_items(submenu, group_node)

        for item in node.get("items", []):
            callback = item.get("callback")
            if not callable(callback):
                continue
            if bool(item.get("separator_before", False)):
                self._safe_add_separator(menu)
            menu.add_command(label=str(item.get("label") or ""), command=callback)
            idx = int(menu.index("end"))
            action_key = str(item.get("action_key") or "").strip()
            if action_key:
                self._register_menu_action(action_key, menu, idx)
                self._remember_menu_action_label(str(item.get("label") or ""), action_key)
            initial_state = str(item.get("initial_state") or "normal").strip().lower()
            if initial_state == "disabled":
                try:
                    menu.entryconfigure(idx, state="disabled")
                except Exception:
                    pass
            if bool(item.get("separator_after", False)):
                self._safe_add_separator(menu)

    def _build_action_menubutton(
        self,
        parent: ttk.Frame,
        menu_label: str,
        action_items: List[Dict[str, Any]],
        *,
        pack_side: str = LEFT,
        pack_padx: Any = 6,
    ) -> ttk.Menubutton:
        tree: Dict[str, Any] = {"groups": {}, "items": []}
        for item in action_items:
            group_path = str(item.get("group_path") or "").strip()
            parts = [p.strip() for p in group_path.split("/") if p.strip()]
            node = tree
            for part in parts:
                groups = node.setdefault("groups", {})
                node = groups.setdefault(part, {"groups": {}, "items": []})
            node.setdefault("items", []).append(item)

        menubutton = ttk.Menubutton(parent, text=menu_label, takefocus=True)
        menu = tk.Menu(menubutton, tearoff=False)
        menubutton.configure(menu=menu)
        self._add_menu_items(menu, tree)
        self._bind_menubutton_keyboard(menubutton)
        menubutton.pack(side=pack_side, padx=pack_padx)
        return menubutton

    def _group_actions_into_menus(
        self,
        *,
        parent: ttk.Frame,
        context_key: str,
        menu_specs: List[Dict[str, Any]],
        source_frames: Optional[List[ttk.Frame]] = None,
    ) -> None:
        if not bool(getattr(self, "ui_compact_menus_enabled", True)):
            return
        frames = source_frames or [parent]
        label_buckets: Dict[str, List[ttk.Button]] = {}
        for frame in frames:
            for widget in frame.winfo_children():
                if not isinstance(widget, ttk.Button):
                    continue
                label = str(widget.cget("text") or "").strip()
                if not label:
                    continue
                label_buckets.setdefault(label, []).append(widget)

        for spec in menu_specs:
            menu_label = str(spec.get("menu_label") or "").strip()
            entries = list(spec.get("entries") or [])
            if not menu_label or not entries:
                continue

            action_items: List[Dict[str, Any]] = []
            for entry in entries:
                label = str(entry.get("label") or "").strip()
                if not label:
                    continue
                queue = label_buckets.get(label) or []
                if not queue:
                    continue
                button = queue.pop(0)
                manager = str(button.winfo_manager() or "")
                if manager == "pack":
                    button.pack_forget()
                elif manager == "grid":
                    button.grid_remove()
                elif manager == "place":
                    button.place_forget()

                action_items.append(
                    {
                        "action_key": self._unique_action_key(context_key, label),
                        "label": label,
                        "group_path": str(entry.get("group_path") or "").strip(),
                        "callback": (lambda b=button: b.invoke()),
                        "initial_state": str(button.cget("state") or "normal").strip().lower(),
                        "separator_before": bool(entry.get("separator_before", False)),
                        "separator_after": bool(entry.get("separator_after", False)),
                    }
                )

            if not action_items:
                continue
            self._build_action_menubutton(
                parent,
                menu_label,
                action_items,
                pack_side=str(spec.get("pack_side") or LEFT),
                pack_padx=spec.get("pack_padx", 6),
            )

    def _has_role(self, *allowed_roles: str) -> bool:
        role = normalize_role(self.current_user.get("role", ""))
        if role == "admin":
            return True
        allowed = {normalize_role(r) for r in allowed_roles}
        return role in allowed

    def _require_role(self, action_label: str, *allowed_roles: str) -> bool:
        if self._has_role(*allowed_roles):
            return True
        allowed = ", ".join(sorted({normalize_role(r) for r in allowed_roles}))
        messagebox.showerror("Acces restrictionat", f"Actiunea '{action_label}' necesita rol: {allowed}.")
        return False

    def open_ui_settings_tab(self) -> None:
        if not self._require_role("Setari UI", "admin"):
            return
        if not hasattr(self, "notebook"):
            messagebox.showwarning("Setari UI", "Notebook-ul principal nu este disponibil.")
            return
        if self.tab_settings is None:
            messagebox.showwarning("Setari UI", "Tab-ul Setari nu este disponibil pentru sesiunea curenta.")
            return
        try:
            self.notebook.select(self.tab_settings)
            self.notebook.update_idletasks()
            if self.ui_compact_menus_checkbutton is not None:
                self.ui_compact_menus_checkbutton.focus_set()
            if hasattr(self, "settings_hint_var"):
                self.settings_hint_var.set(
                    "Toggle rapid: 'UI compact menus'. Dupa modificare, salveaza si restarteaza pentru efect complet."
                )
        except Exception as exc:
            messagebox.showerror("Setari UI", f"Nu am putut deschide tab-ul Setari.\n{exc}")

    def _audit(self, action: str, details: str = "", patient_id: Optional[int] = None) -> None:
        try:
            self.db.add_audit_log(self.current_user.get("id"), patient_id, action, details)
            if self._has_role("admin", "medic") and hasattr(self, "audit_tree"):
                self.refresh_audit()
        except Exception:
            pass

    @staticmethod
    def _new_correlation_id() -> str:
        return secrets.token_hex(12)

    def _record_job_execution(
        self,
        *,
        job_name: str,
        status: str,
        start_perf: float,
        details: Dict[str, Any],
        correlation_id: str,
    ) -> None:
        try:
            self.db.record_job_execution(
                job_name=(job_name or "").strip() or "job",
                status=(status or "").strip() or "ok",
                duration_ms=elapsed_ms(start_perf),
                details_json=json.dumps(details or {}, ensure_ascii=False),
                correlation_id=(correlation_id or "").strip(),
            )
        except Exception:
            pass

    def _is_critical_alert_reasons(self, reason_text: str) -> bool:
        parts = [p.strip().lower() for p in (reason_text or "").split(",") if p.strip()]
        if len(parts) >= 2:
            return True
        for p in parts:
            if p.startswith(("spo2=", "resp=", "puls=")):
                return True
        return False

    def _init_alert_monitoring(self) -> None:
        try:
            initial = self._read_dashboard_vital_alerts_api_first(department="", hours=24, limit=1)
            self.alert_last_seen_id = int(initial[0]["id"]) if initial else 0
            self.alert_status_var.set(
                f"Alerte critice: monitorizare activa ({self.alert_poll_seconds}s)"
            )
            self.alert_status_label.config(fg="#b91c1c")
        except Exception:
            self.alert_last_seen_id = 0
            self.alert_status_var.set("Alerte critice: monitorizare indisponibila")
            self.alert_status_label.config(fg="#b91c1c")
        self._schedule_alert_poll()

    def _schedule_alert_poll(self) -> None:
        if self.alert_poll_job:
            try:
                self.root.after_cancel(self.alert_poll_job)
            except Exception:
                pass
            self.alert_poll_job = None
        self.alert_poll_job = self.root.after(self.alert_poll_seconds * 1000, self._poll_critical_alerts)

    def mute_alerts_5m(self) -> None:
        self.alert_muted_until = datetime.now() + timedelta(minutes=5)
        mute_text = self.alert_muted_until.strftime("%H:%M:%S")
        self.alert_status_var.set(f"Alerte critice: mutate pana la {mute_text}")
        self.alert_status_label.config(fg="#92400e")

    def _poll_critical_alerts(self) -> None:
        try:
            self.check_new_critical_alerts(show_popup=True)
            self.check_escalation_critical_alerts()
        finally:
            self._schedule_alert_poll()

    def check_new_critical_alerts(self, show_popup: bool = True) -> None:
        department = ""
        if hasattr(self, "dashboard_department_var"):
            department = self.dashboard_department_var.get().strip()
        alerts = self._read_dashboard_vital_alerts_api_first(department=department, hours=24, limit=200)
        if not alerts:
            if self.alert_muted_until and datetime.now() >= self.alert_muted_until:
                self.alert_muted_until = None
                self.alert_status_var.set(
                    f"Alerte critice: monitorizare activa ({self.alert_poll_seconds}s)"
                )
                self.alert_status_label.config(fg="#b91c1c")
            return

        max_id = max(int(a["id"]) for a in alerts)
        acked_ids = self.db.get_acknowledged_vital_ids([int(a["id"]) for a in alerts])
        new_alerts = [a for a in alerts if int(a["id"]) > self.alert_last_seen_id]
        self.alert_last_seen_id = max(self.alert_last_seen_id, max_id)
        critical_new = [
            a
            for a in new_alerts
            if self._is_critical_alert_reasons(a["reasons"]) and int(a["id"]) not in acked_ids
        ]

        if self.alert_muted_until:
            if datetime.now() < self.alert_muted_until:
                return
            self.alert_muted_until = None
            self.alert_status_var.set(f"Alerte critice: monitorizare activa ({self.alert_poll_seconds}s)")
            self.alert_status_label.config(fg="#b91c1c")

        if critical_new:
            self._dispatch_external_notifications(critical_new)

        if not critical_new or not show_popup:
            return

        preview_lines: List[str] = []
        for row in sorted(critical_new, key=lambda x: int(x["id"]))[:3]:
            preview_lines.append(
                f"- {row['last_name']} {row['first_name']} | {row.get('mrn') or '-'} | {row['reasons']}"
            )
        extra = len(critical_new) - len(preview_lines)
        body = "\n".join(preview_lines)
        if extra > 0:
            body += f"\n... si inca {extra} alerta(e)."
        message = "Alerte vitale critice noi:\n\n" + body
        self._audit(
            "critical_alert_popup",
            self._audit_details_from_pairs(("count", len(critical_new))),
        )
        self.alert_status_var.set(f"Alerte critice noi: {len(critical_new)}")
        self.alert_status_label.config(fg="#b91c1c")
        messagebox.showwarning("Alerte critice", message)

    def check_escalation_critical_alerts(self) -> None:
        if not self.notify_enabled or not self._notification_channels_configured():
            return
        if self.alert_muted_until and datetime.now() < self.alert_muted_until:
            return
        if self.alert_escalation_last_sent_at is not None:
            elapsed = (datetime.now() - self.alert_escalation_last_sent_at).total_seconds()
            if elapsed < self.alert_escalation_cooldown_seconds:
                return

        department = self.dashboard_department_var.get().strip() if hasattr(self, "dashboard_department_var") else ""
        alerts = self._read_dashboard_vital_alerts_api_first(department=department, hours=24, limit=1000)
        if not alerts:
            return

        acked_ids = self.db.get_acknowledged_vital_ids([int(a["id"]) for a in alerts])
        threshold = datetime.now() - timedelta(minutes=self.alert_escalation_minutes)
        escalation_alerts: List[Dict[str, Any]] = []
        for row in alerts:
            if int(row["id"]) in acked_ids:
                continue
            if not self._is_critical_alert_reasons(row.get("reasons", "")):
                continue
            try:
                rec_dt = datetime.strptime(str(row["recorded_at"]), "%Y-%m-%d %H:%M:%S")
            except ValueError:
                continue
            if rec_dt <= threshold:
                escalation_alerts.append(row)

        if not escalation_alerts:
            return

        self._dispatch_external_notifications(escalation_alerts, event_type="critical_vital_alert_escalation")
        self.alert_escalation_last_sent_at = datetime.now()
        self._audit(
            "critical_alert_escalation",
            self._audit_details_from_pairs(("count", len(escalation_alerts))),
        )
        self.alert_status_var.set(f"Escaladare alerte critice: {len(escalation_alerts)}")
        self.alert_status_label.config(fg="#b91c1c")

    def _notification_channels_configured(self) -> bool:
        has_telegram = bool(self.notify_telegram_token and self.notify_telegram_chat_id)
        has_webhook = bool(self.notify_webhook_url)
        has_email = bool(self.notify_smtp_host and self.notify_email_from and self.notify_email_to)
        return has_telegram or has_webhook or has_email

    def _build_external_alert_message(self, critical_alerts: List[Dict[str, Any]]) -> str:
        lines = [
            f"[{DEFAULT_HOSPITAL_NAME}] ALERTA VITALA CRITICA",
            f"Timp: {now_ts()}",
            f"Numar alerte: {len(critical_alerts)}",
            "",
        ]
        for row in critical_alerts[:5]:
            lines.append(
                f"- Pacient: {row['last_name']} {row['first_name']} | MRN: {row.get('mrn') or '-'} | "
                f"Timp: {row['recorded_at']} | Alerta: {row['reasons']}"
            )
        extra = len(critical_alerts) - min(5, len(critical_alerts))
        if extra > 0:
            lines.append(f"... si inca {extra} alerta(e).")
        return "\n".join(lines)

    def _dispatch_external_notifications(self, critical_alerts: List[Dict[str, Any]], event_type: str = "critical_vital_alert") -> None:
        if not self.notify_enabled:
            return
        if not self._notification_channels_configured():
            return
        if self.notify_busy:
            return
        if self.notify_last_sent_at is not None and self.notify_cooldown_seconds > 0:
            elapsed = (datetime.now() - self.notify_last_sent_at).total_seconds()
            if elapsed < self.notify_cooldown_seconds:
                return

        message = self._build_external_alert_message(critical_alerts)
        payload = {
            "event": event_type,
            "hospital": DEFAULT_HOSPITAL_NAME,
            "generated_at": now_ts(),
            "count": len(critical_alerts),
            "alerts": [
                {
                    "id": int(item["id"]),
                    "patient_id": int(item["patient_id"]),
                    "patient_name": f"{item['last_name']} {item['first_name']}",
                    "mrn": item.get("mrn") or "",
                    "recorded_at": item["recorded_at"],
                    "reasons": item["reasons"],
                    "notes": item.get("notes") or "",
                }
                for item in critical_alerts
            ],
            "message": message,
        }

        self.notify_busy = True
        thread = threading.Thread(
            target=self._send_external_notifications_worker,
            args=(message, payload),
            daemon=True,
        )
        thread.start()

    def _send_external_notifications_worker(self, message: str, payload: Dict[str, Any]) -> None:
        results: List[str] = []
        success_count = 0
        fail_count = 0

        if self.notify_telegram_token and self.notify_telegram_chat_id:
            ok, info = self._send_telegram_notification(message)
            results.append(self._format_notification_channel_result("telegram", ok, info))
            success_count += 1 if ok else 0
            fail_count += 0 if ok else 1

        if self.notify_webhook_url:
            ok, info = self._send_webhook_notification(payload)
            results.append(self._format_notification_channel_result("webhook", ok, info))
            success_count += 1 if ok else 0
            fail_count += 0 if ok else 1

        if self.notify_smtp_host and self.notify_email_from and self.notify_email_to:
            ok, info = self._send_email_notification(message)
            results.append(self._format_notification_channel_result("email", ok, info))
            success_count += 1 if ok else 0
            fail_count += 0 if ok else 1

        self.root.after(0, lambda: self._on_external_notifications_done(success_count, fail_count, results))

    def _init_backup_scheduler(self) -> None:
        if not self.backup_enabled:
            return
        self._schedule_backup_job(delay_seconds=30)

    def _schedule_backup_job(self, delay_seconds: Optional[int] = None) -> None:
        if self.backup_job:
            try:
                self.root.after_cancel(self.backup_job)
            except Exception:
                pass
            self.backup_job = None
        seconds = delay_seconds if delay_seconds is not None else self.backup_interval_minutes * 60
        self.backup_job = self.root.after(max(10, int(seconds)) * 1000, self._run_scheduled_backup)

    def _run_scheduled_backup(self) -> None:
        try:
            self._create_backup(trigger="auto")
        except Exception:
            pass
        finally:
            self._schedule_backup_job()

    def _cancel_integration_jobs(self) -> None:
        for attr in ("integration_worker_job", "medis_pull_job", "shadow_sync_job"):
            handle = getattr(self, attr, None)
            if not handle:
                continue
            try:
                self.root.after_cancel(handle)
            except Exception:
                pass
            setattr(self, attr, None)

    def _schedule_integration_jobs(self) -> None:
        self._cancel_integration_jobs()
        self.integration_worker_job = self.root.after(15000, self._run_integration_worker_tick)
        if self._integration_live_ready("medis") and self.medis_endpoint_results_pull:
            self.medis_pull_job = self.root.after(
                max(10, int(self.medis_pull_interval_seconds)) * 1000,
                self._run_medis_pull_tick,
            )
        if bool(getattr(self, "api_internal_postgres_shadow_enabled", False)):
            self.shadow_sync_job = self.root.after(
                max(5, int(getattr(self, "api_internal_postgres_shadow_interval_seconds", 60))) * 1000,
                self._run_shadow_sync_tick,
            )

    def _run_integration_worker_tick(self) -> None:
        corr = self._new_correlation_id()
        set_correlation_id(corr)
        started = time.perf_counter()
        status = "ok"
        details: Dict[str, Any] = {
            "source": "auto_tick",
            "processed": 0,
            "success": 0,
            "retry": 0,
            "failed": 0,
            "last_error": "",
        }
        try:
            with traced_operation(
                "desktop.integration_queue_tick",
                {
                    "correlation_id": corr,
                    "worker": "ui",
                },
            ):
                if self.integration_dispatcher is not None:
                    summary = self.integration_dispatcher.process_due_jobs(
                        max_jobs=20,
                        lease_owner=f"ui-{os.getpid()}",
                    )
                    details.update(
                        {
                            "processed": int(summary.processed or 0),
                            "success": int(summary.success or 0),
                            "retry": int(summary.retriable_failures or 0),
                            "failed": int(summary.permanent_failures or 0),
                            "last_error": str(summary.last_error or ""),
                        }
                    )
                    if summary.success > 0:
                        self._audit(
                            "integration_queue_success",
                            self._audit_details_from_pairs(
                                ("processed", summary.processed),
                                ("success", summary.success),
                            ),
                        )
                    if summary.permanent_failures > 0:
                        self._audit(
                            "integration_queue_permanent_failure",
                            self._audit_details_from_pairs(
                                ("processed", summary.processed),
                                ("failed", summary.permanent_failures),
                                ("error", summary.last_error),
                            ),
                        )
        except Exception as exc:
            status = "error"
            details["error"] = str(exc)
            self._audit(
                "integration_queue_tick_error",
                self._audit_details_from_pairs(("error", str(exc))),
            )
            self.enterprise_logger.error("integration_queue_tick failed: %s", str(exc))
        finally:
            self._record_job_execution(
                job_name="integration_queue_tick",
                status=status,
                start_perf=started,
                details=details,
                correlation_id=corr,
            )
            self.integration_worker_job = self.root.after(15000, self._run_integration_worker_tick)

    def _run_medis_pull_tick(self) -> None:
        corr = self._new_correlation_id()
        set_correlation_id(corr)
        started = time.perf_counter()
        status = "ok"
        details: Dict[str, Any] = {"source": "auto_tick"}
        try:
            with traced_operation(
                "desktop.medis_pull_tick",
                {"correlation_id": corr},
            ):
                pulled, applied = self.pull_medis_results_now(show_feedback=False)
                details["pulled"] = int(pulled or 0)
                details["applied"] = int(applied or 0)
        except Exception as exc:
            status = "error"
            details["error"] = str(exc)
            self._audit(
                "medis_pull_tick_error",
                self._audit_details_from_pairs(("error", str(exc))),
            )
            self.enterprise_logger.error("medis_pull_tick failed: %s", str(exc))
        finally:
            self._record_job_execution(
                job_name="medis_pull_tick",
                status=status,
                start_perf=started,
                details=details,
                correlation_id=corr,
            )
            self.medis_pull_job = self.root.after(
                max(10, int(self.medis_pull_interval_seconds)) * 1000,
                self._run_medis_pull_tick,
            )

    def _run_shadow_sync_tick(self) -> None:
        if not bool(getattr(self, "api_internal_postgres_shadow_enabled", False)):
            self.shadow_sync_job = None
            return
        corr = self._new_correlation_id()
        set_correlation_id(corr)
        started = time.perf_counter()
        status = "ok"
        details: Dict[str, Any] = {"source": "auto_tick"}
        try:
            with traced_operation(
                "desktop.shadow_sync_tick",
                {"correlation_id": corr},
            ):
                summary = self.process_shadow_sync_now(
                    show_feedback=False,
                    source="auto_tick",
                    enforce_role=False,
                )
                details.update(
                    {
                        "processed": int(summary.get("processed") or 0),
                        "synced": int(summary.get("synced") or 0),
                        "retried": int(summary.get("retried") or 0),
                        "failed": int(summary.get("failed") or 0),
                        "pending_after": int(summary.get("pending_after") or 0),
                        "error_rate_24h": float(summary.get("error_rate_24h") or 0.0),
                        "auto_stopped": bool(summary.get("auto_stopped", False)),
                        "last_error": str(summary.get("last_error") or ""),
                    }
                )
                if bool(summary.get("auto_stopped", False)):
                    self.api_internal_postgres_shadow_enabled = False
                    try:
                        self.db.set_setting("API_INTERNAL_POSTGRES_SHADOW_ENABLED", "0")
                    except Exception:
                        pass
                    self._audit(
                        "shadow_sync_auto_stop",
                        self._audit_details_from_pairs(
                            ("error_rate_24h", summary.get("error_rate_24h")),
                            ("threshold", self.api_internal_postgres_shadow_stop_on_error_rate),
                        ),
                    )
        except Exception as exc:
            status = "error"
            details["error"] = str(exc)
            self.enterprise_logger.error("shadow_sync_tick failed: %s", str(exc))
        finally:
            self._record_job_execution(
                job_name="shadow_sync_tick",
                status=status,
                start_perf=started,
                details=details,
                correlation_id=corr,
            )
            if bool(getattr(self, "api_internal_postgres_shadow_enabled", False)):
                self.shadow_sync_job = self.root.after(
                    max(5, int(getattr(self, "api_internal_postgres_shadow_interval_seconds", 60))) * 1000,
                    self._run_shadow_sync_tick,
                )
            else:
                self.shadow_sync_job = None

    def _prune_old_backups(self) -> None:
        cutoff = datetime.now() - timedelta(days=self.backup_retention_days)
        for file_path in BACKUPS_DIR.glob("pacienti_ai_backup_*.db"):
            try:
                mtime = datetime.fromtimestamp(file_path.stat().st_mtime)
                if mtime < cutoff:
                    file_path.unlink(missing_ok=True)
            except Exception:
                pass

    def _create_backup(self, trigger: str = "manual") -> Path:
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        out_path = BACKUPS_DIR / f"pacienti_ai_backup_{stamp}.db"
        self.db.create_backup_file(out_path)
        self._prune_old_backups()
        self._audit(
            "db_backup",
            self._audit_details_from_pairs(
                ("trigger", trigger),
                ("path", out_path),
            ),
        )
        return out_path

    def create_manual_backup(self) -> None:
        if not self._require_role("Backup baza date", "admin", "medic"):
            return
        try:
            out_path = self._create_backup(trigger="manual")
            messagebox.showinfo("Backup", f"Backup creat:\n{out_path}")
        except Exception as exc:
            messagebox.showerror("Backup", f"Nu am putut crea backup: {exc}")

    def restore_backup_dialog(self) -> None:
        if not self._require_role("Restore backup", "admin"):
            return
        backup_path = filedialog.askopenfilename(
            title="Selecteaza backup DB",
            initialdir=str(BACKUPS_DIR),
            filetypes=(("SQLite DB", "*.db"), ("Toate fisierele", "*.*")),
        )
        if not backup_path:
            return
        if not messagebox.askyesno(
            "Confirmare restore",
            "Restore va inlocui datele curente din aplicatie. Continui?",
        ):
            return
        try:
            self.db.restore_from_backup_file(Path(backup_path))
            self._audit(
                "db_restore",
                self._audit_details_from_pairs(("path", backup_path)),
            )
            self.refresh_patients()
            self.new_patient()
            self.refresh_operational_views()
            if self._has_role("admin", "medic"):
                self.refresh_audit()
            if self._has_role("admin"):
                self.refresh_users()
            messagebox.showinfo("Restore", "Restore finalizat cu succes.")
        except Exception as exc:
            messagebox.showerror("Restore", f"Restore esuat: {exc}")

    def _send_telegram_notification(self, message: str) -> tuple[bool, str]:
        try:
            url = f"https://api.telegram.org/bot{self.notify_telegram_token}/sendMessage"
            payload = urllib_parse.urlencode(
                {
                    "chat_id": self.notify_telegram_chat_id,
                    "text": message,
                    "disable_web_page_preview": "true",
                }
            ).encode("utf-8")
            req = urllib_request.Request(url, data=payload, method="POST")
            req.add_header("Content-Type", "application/x-www-form-urlencoded")
            with urllib_request.urlopen(req, timeout=15) as resp:
                _ = resp.read()
            return True, "sent"
        except Exception as exc:
            return False, str(exc)

    def _send_webhook_notification(self, payload: Dict[str, Any]) -> tuple[bool, str]:
        try:
            body = json.dumps(payload).encode("utf-8")
            req = urllib_request.Request(self.notify_webhook_url, data=body, method="POST")
            req.add_header("Content-Type", "application/json")
            with urllib_request.urlopen(req, timeout=15) as resp:
                _ = resp.read()
            return True, "sent"
        except Exception as exc:
            return False, str(exc)

    def _send_email_notification(self, message: str) -> tuple[bool, str]:
        try:
            email_msg = EmailMessage()
            email_msg["Subject"] = f"[{DEFAULT_HOSPITAL_NAME}] Alerta vitala critica"
            email_msg["From"] = self.notify_email_from
            email_msg["To"] = ", ".join(self.notify_email_to)
            email_msg.set_content(message)

            with smtplib.SMTP(self.notify_smtp_host, self.notify_smtp_port, timeout=20) as smtp:
                smtp.ehlo()
                if self.notify_smtp_port in (587, 25):
                    smtp.starttls()
                    smtp.ehlo()
                if self.notify_smtp_user:
                    smtp.login(self.notify_smtp_user, self.notify_smtp_pass)
                smtp.send_message(email_msg)
            return True, "sent"
        except Exception as exc:
            return False, str(exc)

    @staticmethod
    def _format_notification_channel_result(channel: str, ok: bool, info: str) -> str:
        return f"{str(channel or '').strip()}:{'ok' if ok else 'fail'}:{str(info or '').strip()}"

    @staticmethod
    def _normalize_notification_channels_detail(details: Any) -> str:
        if isinstance(details, (list, tuple)):
            return " | ".join([str(part or "").strip() for part in details if str(part or "").strip()]) or "-"
        return " | ".join([part.strip() for part in str(details or "").split(";") if part.strip()]) or "-"

    @staticmethod
    def _external_notification_audit_details(*, success_count: int, fail_count: int, channels_detail: str) -> str:
        return App._audit_details_from_pairs(
            ("success", success_count),
            ("fail", fail_count),
            ("channels", channels_detail),
        )

    def _on_external_notifications_done(self, success_count: int, fail_count: int, details: Any) -> None:
        self.notify_busy = False
        channels_detail = self._normalize_notification_channels_detail(details)
        if success_count > 0:
            self.notify_last_sent_at = datetime.now()
            self._audit(
                "external_alert_notification_sent",
                self._external_notification_audit_details(
                    success_count=success_count,
                    fail_count=fail_count,
                    channels_detail=channels_detail,
                ),
            )
            self.alert_status_var.set(
                f"Alerte critice: notificari externe trimise ({success_count} canal(e))"
            )
            self.alert_status_label.config(fg="#065f46")
            return
        if fail_count > 0:
            self._audit(
                "external_alert_notification_failed",
                self._external_notification_audit_details(
                    success_count=success_count,
                    fail_count=fail_count,
                    channels_detail=channels_detail,
                ),
            )
            self.alert_status_var.set("Alerte critice: notificari externe esuate")
            self.alert_status_label.config(fg="#b91c1c")

    def test_external_notifications(self) -> None:
        if not self._require_role("Test notificari externe", "admin", "medic", "asistent", "receptie"):
            return
        if not self.notify_enabled:
            messagebox.showinfo("Notificari", "ALERT_NOTIFY_ENABLED este dezactivat.")
            return
        if not self._notification_channels_configured():
            messagebox.showinfo(
                "Notificari",
                "Nu exista canale configurate. Seteaza Telegram, Webhook sau SMTP in variabilele de mediu.",
            )
            return
        fake_alert = {
            "id": 0,
            "patient_id": self.current_patient_id or 0,
            "first_name": "Pacient",
            "last_name": "Test",
            "mrn": "-",
            "recorded_at": now_ts(),
            "reasons": "spo2=88, puls=130",
            "notes": "Test notificare externa",
        }
        self.notify_last_sent_at = None
        self._dispatch_external_notifications([fake_alert])

