    def _build_partners_tab(self, parent: ttk.Frame) -> None:
        frame = ttk.Frame(parent)
        frame.pack(fill=BOTH, expand=True, padx=10, pady=10)

        filters = ttk.Frame(frame)
        filters.pack(fill="x", pady=(0, 6))
        self.partner_filter_search_var = tk.StringVar()
        self.partner_filter_type_var = tk.StringVar(value="")
        self.partner_filter_active_only_var = tk.BooleanVar(value=True)
        ttk.Label(filters, text="Cauta").pack(side=LEFT)
        ttk.Entry(filters, textvariable=self.partner_filter_search_var, width=28).pack(side=LEFT, padx=(6, 10))
        ttk.Label(filters, text="Tip").pack(side=LEFT)
        ttk.Combobox(
            filters,
            textvariable=self.partner_filter_type_var,
            state="readonly",
            values=("", "supplier", "lab", "pharmacy", "payer", "insurer", "other"),
            width=14,
        ).pack(side=LEFT, padx=(6, 10))
        ttk.Checkbutton(
            filters,
            text="Doar activi",
            variable=self.partner_filter_active_only_var,
        ).pack(side=LEFT)
        ttk.Button(filters, text="Filtreaza", command=self.refresh_partners).pack(side=LEFT, padx=8)
        ttk.Button(filters, text="Curata", command=self.reset_partner_filters).pack(side=LEFT, padx=6)

        list_wrap = ttk.LabelFrame(frame, text="Registru parteneri")
        list_wrap.pack(fill=BOTH, expand=True)
        cols = ("code", "name", "type", "fiscal", "city", "active", "updated")
