    def _selected_partner_id(self) -> Optional[int]:
        if not hasattr(self, "partner_tree"):
            return None
        selected = self.partner_tree.selection()
        if not selected:
            return None
        try:
            return int(selected[0])
        except Exception:
            return None

    def reset_partner_filters(self) -> None:
        if hasattr(self, "partner_filter_search_var"):
            self.partner_filter_search_var.set("")
        if hasattr(self, "partner_filter_type_var"):
            self.partner_filter_type_var.set("")
        if hasattr(self, "partner_filter_active_only_var"):
            self.partner_filter_active_only_var.set(True)
        self.refresh_partners()

    def new_partner(self) -> None:
        if hasattr(self, "partner_tree"):
            self.partner_tree.selection_remove(self.partner_tree.selection())
        for key, var in getattr(self, "partner_form_vars", {}).items():
            if key == "country":
                var.set("RO")
            elif key == "partner_type":
                var.set("supplier")
            else:
                var.set("")
        if hasattr(self, "partner_active_var"):
            self.partner_active_var.set(True)
        self.refresh_partner_contacts()
        self.refresh_partner_bank_accounts()

    def refresh_partners(self) -> None:
        if not hasattr(self, "partner_tree"):
            return
        selected = self._selected_partner_id()
        for iid in self.partner_tree.get_children():
            self.partner_tree.delete(iid)
        self.partner_map.clear()
        rows = self.db.list_business_partners(
            search=self.partner_filter_search_var.get() if hasattr(self, "partner_filter_search_var") else "",
            partner_type=self.partner_filter_type_var.get() if hasattr(self, "partner_filter_type_var") else "",
            active_only=bool(self.partner_filter_active_only_var.get())
            if hasattr(self, "partner_filter_active_only_var")
            else False,
            limit=1000,
        )
        for row in rows:
            iid = str(row["id"])
            self.partner_map[iid] = dict(row)
            self.partner_tree.insert(
                "",
                END,
                iid=iid,
                values=(
                    row.get("code") or "",
                    row.get("name") or "",
                    row.get("partner_type") or "",
                    row.get("fiscal_code") or "",
                    row.get("city") or "",
                    "DA" if int(row.get("active") or 0) else "NU",
                    row.get("updated_at") or "",
                ),
            )
        if selected and self.partner_tree.exists(str(selected)):
            self.partner_tree.selection_set(str(selected))
            self.partner_tree.focus(str(selected))
        self._refresh_partner_and_cost_center_reference_data()

    def on_partner_select(self, _event: Any = None) -> None:
        partner_id = self._selected_partner_id()
        if not partner_id:
            self.new_partner()
            return
        row = self.partner_map.get(str(partner_id))
        if not row:
            fetched = self.db.get_business_partner(partner_id)
            row = dict(fetched) if fetched else None
        if not row:
            return
        for key in (
            "code",
            "name",
            "partner_type",
            "fiscal_code",
            "reg_com",
            "country",
            "city",
            "address",
            "email",
            "phone",
        ):
            if key in self.partner_form_vars:
                self.partner_form_vars[key].set(str(row.get(key) or ""))
        self.partner_active_var.set(bool(int(row.get("active") or 0)))
        self.refresh_partner_contacts()
        self.refresh_partner_bank_accounts()

    def save_partner(self) -> None:
        if not self._require_role("Salveaza partener", "admin", "medic", "receptie"):
            return
        payload: Dict[str, Any] = {k: v.get().strip() for k, v in self.partner_form_vars.items()}
        payload["active"] = bool(self.partner_active_var.get())
        partner_id = self._selected_partner_id()
        try:
            if partner_id:
                self.db.update_business_partner(partner_id, payload)
                saved_id = partner_id
                action = "update_business_partner"
            else:
                saved_id = self.db.create_business_partner(payload)
                action = "create_business_partner"
        except ValueError as exc:
            messagebox.showerror("Parteneri", str(exc))
            return
        self._audit(
            action,
            self._audit_details_from_pairs(("partner_id", saved_id), ("code", payload.get("code", ""))),
        )
        self.refresh_partners()
        if hasattr(self, "partner_tree") and self.partner_tree.exists(str(saved_id)):
            self.partner_tree.selection_set(str(saved_id))
            self.partner_tree.focus(str(saved_id))
            self.on_partner_select()

    def delete_selected_partner(self) -> None:
        if not self._require_role("Sterge partener", "admin"):
            return
        partner_id = self._selected_partner_id()
        if not partner_id:
            messagebox.showwarning("Parteneri", "Selecteaza un partener.")
            return
        decision = messagebox.askyesno("Parteneri", "Stergi partenerul selectat?")
        if not decision:
            return
        try:
            self.db.delete_business_partner(partner_id)
        except ValueError as exc:
            messagebox.showerror("Parteneri", str(exc))
            return
        self._audit(
            "delete_business_partner",
            self._audit_details_from_pairs(("partner_id", partner_id)),
        )
        self.new_partner()
        self.refresh_partners()

    def refresh_partner_contacts(self) -> None:
        if not hasattr(self, "partner_contacts_tree"):
            return
        for iid in self.partner_contacts_tree.get_children():
            self.partner_contacts_tree.delete(iid)
        partner_id = self._selected_partner_id()
        if not partner_id:
            return
        rows = self.db.list_business_partner_contacts(partner_id)
        for row in rows:
            iid = str(row["id"])
            self.partner_contacts_tree.insert(
                "",
                END,
                iid=iid,
                values=(
                    row.get("name") or "",
                    row.get("role") or "",
                    row.get("email") or "",
                    row.get("phone") or "",
                    "DA" if int(row.get("is_primary") or 0) else "NU",
                ),
            )

    def add_partner_contact(self) -> None:
        if not self._require_role("Adauga contact partener", "admin", "medic", "receptie"):
            return
        partner_id = self._selected_partner_id()
        if not partner_id:
            messagebox.showwarning("Parteneri", "Salveaza/selecteaza partenerul inainte de contact.")
            return
        try:
            contact_id = self.db.add_business_partner_contact(
                partner_id=partner_id,
                name=self.partner_contact_vars["name"].get(),
                role=self.partner_contact_vars["role"].get(),
                email=self.partner_contact_vars["email"].get(),
                phone=self.partner_contact_vars["phone"].get(),
                is_primary=bool(self.partner_contact_primary_var.get()),
            )
        except ValueError as exc:
            messagebox.showerror("Parteneri", str(exc))
            return
        self._audit(
            "add_business_partner_contact",
            self._audit_details_from_pairs(("partner_id", partner_id), ("contact_id", contact_id)),
        )
        for var in self.partner_contact_vars.values():
            var.set("")
        self.partner_contact_primary_var.set(False)
        self.refresh_partner_contacts()

    def delete_selected_partner_contact(self) -> None:
        if not self._require_role("Sterge contact partener", "admin", "medic"):
            return
        partner_id = self._selected_partner_id()
        selected = self.partner_contacts_tree.selection() if hasattr(self, "partner_contacts_tree") else ()
        if not partner_id or not selected:
            messagebox.showwarning("Parteneri", "Selecteaza un contact.")
            return
        try:
            contact_id = int(selected[0])
        except Exception:
            return
        self.db.delete_business_partner_contact(contact_id)
        self._audit(
            "delete_business_partner_contact",
            self._audit_details_from_pairs(("partner_id", partner_id), ("contact_id", contact_id)),
        )
        self.refresh_partner_contacts()

    def refresh_partner_bank_accounts(self) -> None:
        if not hasattr(self, "partner_bank_accounts_tree"):
            return
        for iid in self.partner_bank_accounts_tree.get_children():
            self.partner_bank_accounts_tree.delete(iid)
        partner_id = self._selected_partner_id()
        if not partner_id:
            return
        rows = self.db.list_business_partner_bank_accounts(partner_id)
        for row in rows:
            iid = str(row["id"])
            self.partner_bank_accounts_tree.insert(
                "",
                END,
                iid=iid,
                values=(
                    row.get("bank_name") or "",
                    row.get("iban") or "",
                    row.get("currency") or "",
                    "DA" if int(row.get("is_default") or 0) else "NU",
                ),
            )

    def add_partner_bank_account(self) -> None:
        if not self._require_role("Adauga cont partener", "admin", "medic", "receptie"):
            return
        partner_id = self._selected_partner_id()
        if not partner_id:
            messagebox.showwarning("Parteneri", "Salveaza/selecteaza partenerul inainte de cont bancar.")
            return
        try:
            bank_id = self.db.add_business_partner_bank_account(
                partner_id=partner_id,
                bank_name=self.partner_bank_vars["bank_name"].get(),
                iban=self.partner_bank_vars["iban"].get(),
                currency=self.partner_bank_vars["currency"].get(),
                is_default=bool(self.partner_bank_default_var.get()),
            )
        except ValueError as exc:
            messagebox.showerror("Parteneri", str(exc))
            return
        self._audit(
            "add_business_partner_bank_account",
            self._audit_details_from_pairs(("partner_id", partner_id), ("bank_id", bank_id)),
        )
        self.partner_bank_vars["bank_name"].set("")
        self.partner_bank_vars["iban"].set("")
        self.partner_bank_vars["currency"].set("RON")
        self.partner_bank_default_var.set(False)
        self.refresh_partner_bank_accounts()

    def delete_selected_partner_bank_account(self) -> None:
        if not self._require_role("Sterge cont partener", "admin", "medic"):
            return
        partner_id = self._selected_partner_id()
        selected = self.partner_bank_accounts_tree.selection() if hasattr(self, "partner_bank_accounts_tree") else ()
        if not partner_id or not selected:
            messagebox.showwarning("Parteneri", "Selecteaza un cont bancar.")
            return
        try:
            bank_id = int(selected[0])
        except Exception:
            return
        self.db.delete_business_partner_bank_account(bank_id)
        self._audit(
            "delete_business_partner_bank_account",
            self._audit_details_from_pairs(("partner_id", partner_id), ("bank_id", bank_id)),
        )
        self.refresh_partner_bank_accounts()

    def _refresh_partner_and_cost_center_reference_data(self) -> None:
        partner_options = ["-"]
        self.partner_option_map = {}
        for row in self.db.list_business_partners(active_only=True, limit=2000):
            label = f"{row.get('code') or ''} - {row.get('name') or ''}".strip(" -")
            if not label:
                label = f"Partener #{row['id']}"
            partner_options.append(label)
            self.partner_option_map[label] = int(row["id"])

        cost_center_options = ["-"]
        self.cost_center_option_map = {}
        for row in self.db.list_cost_centers(include_inactive=False):
            label = f"{row.get('code') or ''} - {row.get('name') or ''}".strip(" -")
            if not label:
                label = f"CC #{row['id']}"
            cost_center_options.append(label)
            self.cost_center_option_map[label] = int(row["id"])

        for widget_attr, var_attr in (
            ("consumption_partner_combo", "consumption_partner_var"),
            ("invoice_partner_combo", "invoice_partner_var"),
        ):
            if hasattr(self, widget_attr) and hasattr(self, var_attr):
                widget = getattr(self, widget_attr)
                var = getattr(self, var_attr)
                current = str(var.get() or "")
                try:
                    widget.configure(values=tuple(partner_options))
                except Exception:
                    pass
                if current not in partner_options:
                    var.set("-")
        for widget_attr, var_attr in (
            ("consumption_cost_center_combo", "consumption_cost_center_var"),
            ("invoice_cost_center_combo", "invoice_cost_center_var"),
            ("billing_cost_center_combo", "billing_cost_center_var"),
        ):
            if hasattr(self, widget_attr) and hasattr(self, var_attr):
                widget = getattr(self, widget_attr)
                var = getattr(self, var_attr)
                current = str(var.get() or "")
                try:
                    widget.configure(values=tuple(cost_center_options))
                except Exception:
                    pass
                if current not in cost_center_options:
                    var.set("-")

    def _selected_partner_ref_id(self, selected_label: str) -> Optional[int]:
        label = (selected_label or "").strip()
        if not label or label == "-":
            return None
        return self.partner_option_map.get(label)

    def _selected_cost_center_ref_id(self, selected_label: str) -> Optional[int]:
        label = (selected_label or "").strip()
        if not label or label == "-":
            return None
        if label in self.cost_center_option_map:
            return self.cost_center_option_map.get(label)
        return self.cost_center_parent_option_map.get(label)

    def _partner_label_from_id(self, partner_id: Optional[int]) -> str:
        target = int(partner_id or 0)
        if target <= 0:
            return "-"
        for label, value in self.partner_option_map.items():
            if int(value) == target:
                return label
        return "-"

    def _cost_center_label_from_id(self, cost_center_id: Optional[int]) -> str:
        target = int(cost_center_id or 0)
        if target <= 0:
            return "-"
        for label, value in self.cost_center_option_map.items():
            if int(value) == target:
                return label
        for label, value in self.cost_center_parent_option_map.items():
            if int(value) == target:
                return label
        return "-"

    def _selected_cost_center_id(self) -> Optional[int]:
        if not hasattr(self, "cost_center_tree"):
            return None
        selected = self.cost_center_tree.selection()
        if not selected:
            return None
        try:
            return int(selected[0])
        except Exception:
            return None

    def _refresh_cost_center_parent_options(self) -> None:
        if not hasattr(self, "cost_center_parent_combo"):
            return
        options = ["-"]
        self.cost_center_parent_option_map = {}
        for row in self.db.list_cost_centers(include_inactive=True):
            label = f"{row.get('code') or ''} - {row.get('name') or ''}".strip(" -")
            if not label:
                label = f"CC #{row['id']}"
            options.append(label)
            self.cost_center_parent_option_map[label] = int(row["id"])
        current = self.cost_center_parent_var.get() if hasattr(self, "cost_center_parent_var") else "-"
        self.cost_center_parent_combo.configure(values=tuple(options))
        if current not in options:
            self.cost_center_parent_var.set("-")

    def new_cost_center(self) -> None:
        if hasattr(self, "cost_center_tree"):
            self.cost_center_tree.selection_remove(self.cost_center_tree.selection())
        if hasattr(self, "cost_center_code_var"):
            self.cost_center_code_var.set("")
        if hasattr(self, "cost_center_name_var"):
            self.cost_center_name_var.set("")
        if hasattr(self, "cost_center_parent_var"):
            self.cost_center_parent_var.set("-")
        if hasattr(self, "cost_center_active_var"):
            self.cost_center_active_var.set(True)

    def refresh_cost_centers(self) -> None:
        if not hasattr(self, "cost_center_tree"):
            return
        selected = self._selected_cost_center_id()
        for iid in self.cost_center_tree.get_children():
            self.cost_center_tree.delete(iid)
        self.cost_center_map.clear()
        rows = self.db.list_cost_centers(include_inactive=True)
        for row in rows:
            iid = str(row["id"])
            self.cost_center_map[iid] = dict(row)
            parent_label = ""
            if row.get("parent_id"):
                parent_label = f"{row.get('parent_code') or ''} - {row.get('parent_name') or ''}".strip(" -")
            self.cost_center_tree.insert(
                "",
                END,
                iid=iid,
                values=(
                    row.get("code") or "",
                    row.get("name") or "",
                    parent_label or "-",
                    "DA" if int(row.get("active") or 0) else "NU",
                ),
            )
        if selected and self.cost_center_tree.exists(str(selected)):
            self.cost_center_tree.selection_set(str(selected))
            self.cost_center_tree.focus(str(selected))
        self._refresh_cost_center_parent_options()
        self._refresh_partner_and_cost_center_reference_data()

    def on_cost_center_select(self, _event: Any = None) -> None:
        cc_id = self._selected_cost_center_id()
        if not cc_id:
            return
        row = self.cost_center_map.get(str(cc_id)) or {}
        if not row:
            return
        self.cost_center_code_var.set(str(row.get("code") or ""))
        self.cost_center_name_var.set(str(row.get("name") or ""))
        self.cost_center_active_var.set(bool(int(row.get("active") or 0)))
        parent_label = "-"
        if row.get("parent_id"):
            parent_label = f"{row.get('parent_code') or ''} - {row.get('parent_name') or ''}".strip(" -") or "-"
        self.cost_center_parent_var.set(parent_label)

    def save_cost_center(self) -> None:
        if not self._require_role("Salveaza centru cost", "admin", "medic"):
            return
        code = self.cost_center_code_var.get() if hasattr(self, "cost_center_code_var") else ""
        name = self.cost_center_name_var.get() if hasattr(self, "cost_center_name_var") else ""
        parent_id = self._selected_cost_center_ref_id(
            self.cost_center_parent_var.get() if hasattr(self, "cost_center_parent_var") else "-"
        )
        current_id = self._selected_cost_center_id()
        if current_id and parent_id and int(parent_id) == int(current_id):
            parent_id = None
        try:
            if current_id:
                self.db.update_cost_center(
                    cost_center_id=current_id,
                    code=code,
                    name=name,
                    parent_id=parent_id,
                    active=bool(self.cost_center_active_var.get()),
                )
                saved_id = current_id
                action = "update_cost_center"
            else:
                saved_id = self.db.create_cost_center(
                    code=code,
                    name=name,
                    parent_id=parent_id,
                    active=bool(self.cost_center_active_var.get()),
                )
                action = "create_cost_center"
        except ValueError as exc:
            messagebox.showerror("Centre cost", str(exc))
            return
        self._audit(action, self._audit_details_from_pairs(("cost_center_id", saved_id), ("code", code)))
        self.refresh_cost_centers()
        if hasattr(self, "cost_center_tree") and self.cost_center_tree.exists(str(saved_id)):
            self.cost_center_tree.selection_set(str(saved_id))
            self.cost_center_tree.focus(str(saved_id))

