        ttk.Entry(form, textvariable=self.user_form_vars["username"], width=18).grid(row=0, column=1, sticky="w", padx=6, pady=4)
        ttk.Label(form, text="Nume afisat").grid(row=0, column=2, sticky="w", padx=6, pady=4)
