    def refresh_docnum_rules_preview(self) -> None:
        if not hasattr(self, "docnum_rules_tree"):
            return
        selected = None
        try:
            current = self.docnum_rules_tree.selection()
            selected = current[0] if current else None
        except Exception:
            selected = None
        for iid in self.docnum_rules_tree.get_children():
            self.docnum_rules_tree.delete(iid)
        self.docnum_rules_map.clear()
        rows = self.db.list_document_numbering_rules()
        for row in rows:
            iid = str(row["id"])
            self.docnum_rules_map[iid] = dict(row)
            self.docnum_rules_tree.insert(
                "",
                END,
                iid=iid,
                values=(
                    row.get("id") or "",
                    row.get("document_type") or "",
                    row.get("location") or "",
                    row.get("series") or "",
                    row.get("next_number") or 1,
                    row.get("pad_length") or 6,
                    row.get("reset_policy") or "yearly",
                    "DA" if int(row.get("active") or 0) else "NU",
                ),
            )
        if selected and self.docnum_rules_tree.exists(selected):
            self.docnum_rules_tree.selection_set(selected)
            self.docnum_rules_tree.focus(selected)

    def on_docnum_rule_select(self, _event: Any = None) -> None:
        if not hasattr(self, "docnum_rules_tree"):
            return
        selected = self.docnum_rules_tree.selection()
        if not selected:
            return
        row = self.docnum_rules_map.get(str(selected[0])) or {}
        if not row or not hasattr(self, "docnum_rule_form_vars"):
            return
        self.docnum_rule_form_vars["document_type"].set(str(row.get("document_type") or ""))
        self.docnum_rule_form_vars["location"].set(str(row.get("location") or ""))
        self.docnum_rule_form_vars["series"].set(str(row.get("series") or ""))
        self.docnum_rule_form_vars["prefix"].set(str(row.get("prefix") or ""))
        self.docnum_rule_form_vars["suffix"].set(str(row.get("suffix") or ""))
        self.docnum_rule_form_vars["next_number"].set(str(row.get("next_number") or 1))
        self.docnum_rule_form_vars["pad_length"].set(str(row.get("pad_length") or 6))
        self.docnum_rule_form_vars["reset_policy"].set(str(row.get("reset_policy") or "yearly"))
        self.docnum_rule_active_var.set(bool(int(row.get("active") or 0)))

    def save_docnum_rule_quick(self) -> None:
        if not self._require_role("Salveaza regula numerotare", "admin"):
            return
        if not hasattr(self, "docnum_rule_form_vars"):
            return
        selected_rule_id: Optional[int] = None
        if hasattr(self, "docnum_rules_tree"):
            selected = self.docnum_rules_tree.selection()
            if selected:
                try:
                    selected_rule_id = int(selected[0])
                except Exception:
                    selected_rule_id = None
        try:
            saved_id = self.db.save_document_numbering_rule(
                document_type=self.docnum_rule_form_vars["document_type"].get(),
                location=self.docnum_rule_form_vars["location"].get(),
                series=self.docnum_rule_form_vars["series"].get(),
                prefix=self.docnum_rule_form_vars["prefix"].get(),
                suffix=self.docnum_rule_form_vars["suffix"].get(),
                next_number=int((self.docnum_rule_form_vars["next_number"].get() or "1").strip() or "1"),
                pad_length=int((self.docnum_rule_form_vars["pad_length"].get() or "6").strip() or "6"),
                reset_policy=self.docnum_rule_form_vars["reset_policy"].get(),
                active=bool(self.docnum_rule_active_var.get()),
                rule_id=selected_rule_id,
            )
        except ValueError as exc:
            messagebox.showerror("Numerotare documente", str(exc))
            return
        except Exception as exc:
            messagebox.showerror("Numerotare documente", f"Nu am putut salva regula: {exc}")
            return
        self._audit(
            "save_document_numbering_rule",
            self._audit_details_from_pairs(("rule_id", saved_id)),
        )
        self.refresh_docnum_rules_preview()
        if hasattr(self, "docnum_rules_tree") and self.docnum_rules_tree.exists(str(saved_id)):
            self.docnum_rules_tree.selection_set(str(saved_id))
            self.docnum_rules_tree.focus(str(saved_id))

    def save_admin_settings(self, apply_now: bool) -> None:
        if not self._require_role("Setari aplicatie", "admin"):
            return

        int_rules = {
            "ALERT_POLL_SECONDS": 15,
            "ALERT_NOTIFY_COOLDOWN_SECONDS": 0,
            "ALERT_ESCALATION_MINUTES": 1,
            "ALERT_ESCALATION_COOLDOWN_SECONDS": 60,
            "ALERT_SMTP_PORT": 1,
            "AUTO_BACKUP_INTERVAL_MINUTES": 10,
            "AUTO_BACKUP_RETENTION_DAYS": 1,
            "CARE_WARD_CAPACITY_DEFAULT": 1,
            "OPERATIONAL_BACKLOG_ALERT_THRESHOLD": 1,
            "WATCHLIST_SCORE_HIGH_THRESHOLD": 1,
            "WATCHLIST_SCORE_MEDIUM_THRESHOLD": 1,
            "WATCHLIST_WEIGHT_TRIAGE_1": 0,
            "WATCHLIST_WEIGHT_TRIAGE_2": 0,
            "WATCHLIST_WEIGHT_TRIAGE_3": 0,
            "WATCHLIST_WEIGHT_TRIAGE_4_PLUS": 0,
            "WATCHLIST_WEIGHT_ALERT_UNACK": 0,
            "WATCHLIST_WEIGHT_ALERT_CRITICAL": 0,
            "WATCHLIST_WEIGHT_ORDER_STAT": 0,
            "WATCHLIST_WEIGHT_ORDER_URGENT": 0,
            "WATCHLIST_WEIGHT_ORDER_IN_PROGRESS": 0,
            "LOGIN_LOCK_MAX_ATTEMPTS": 3,
            "LOGIN_LOCK_MINUTES": 1,
            "AI_MAX_OUTPUT_TOKENS": 200,
            "AI_TIMEOUT_SECONDS": 10,
            "AI_CONTEXT_MAX_CHARS": 2000,
            "AI_HISTORY_MESSAGES": 2,
            "SIUI_DRG_TIMEOUT_SECONDS": 3,
            "SIUI_DRG_MAX_RETRIES": 0,
            "MEDIS_TIMEOUT_SECONDS": 3,
            "MEDIS_MAX_RETRIES": 0,
            "MEDIS_PULL_INTERVAL_SECONDS": 10,
            "DOCNUM_LOCK_TIMEOUT_SECONDS": 1,
            "API_INTERNAL_TIMEOUT_SECONDS": 2,
            "API_INTERNAL_POSTGRES_CONNECT_TIMEOUT_SECONDS": 1,
            "API_INTERNAL_POSTGRES_SHADOW_MAX_RETRIES": 0,
            "API_INTERNAL_POSTGRES_SHADOW_BATCH_SIZE": 1,
            "API_INTERNAL_POSTGRES_SHADOW_INTERVAL_SECONDS": 5,
        }

        payload: Dict[str, Any] = {
            "ALERT_NOTIFY_ENABLED": "1" if self.settings_bool_vars["ALERT_NOTIFY_ENABLED"].get() else "0",
            "AUTO_BACKUP_ENABLED": "1" if self.settings_bool_vars["AUTO_BACKUP_ENABLED"].get() else "0",
            "AI_ENABLED": "1" if self.settings_bool_vars["AI_ENABLED"].get() else "0",
            "UI_COMPACT_MENUS_ENABLED": "1" if self.settings_bool_vars["UI_COMPACT_MENUS_ENABLED"].get() else "0",
            "DISCHARGE_REQUIRE_FINAL_DECONT": "1" if self.settings_bool_vars["DISCHARGE_REQUIRE_FINAL_DECONT"].get() else "0",
            "DISCHARGE_REQUIRE_SUMMARY": "1" if self.settings_bool_vars["DISCHARGE_REQUIRE_SUMMARY"].get() else "0",
            "CASE_REQUIRE_SIUI_DRG_SUBMISSION": "1"
            if self.settings_bool_vars["CASE_REQUIRE_SIUI_DRG_SUBMISSION"].get()
            else "0",
            "CASE_REQUIRE_FINANCIAL_CLOSURE": "1"
            if self.settings_bool_vars["CASE_REQUIRE_FINANCIAL_CLOSURE"].get()
            else "0",
            "SIUI_DRG_LIVE_ENABLED": "1" if self.settings_bool_vars["SIUI_DRG_LIVE_ENABLED"].get() else "0",
            "SIUI_DRG_DRY_RUN": "1" if self.settings_bool_vars["SIUI_DRG_DRY_RUN"].get() else "0",
            "MEDIS_LIVE_ENABLED": "1" if self.settings_bool_vars["MEDIS_LIVE_ENABLED"].get() else "0",
            "MEDIS_DRY_RUN": "1" if self.settings_bool_vars["MEDIS_DRY_RUN"].get() else "0",
            "DOCNUM_ENABLE_AUTO": "1" if self.settings_bool_vars["DOCNUM_ENABLE_AUTO"].get() else "0",
            "ENABLE_HTML_EXPORTS_FINANCIAL": "1"
            if self.settings_bool_vars["ENABLE_HTML_EXPORTS_FINANCIAL"].get()
            else "0",
            "ENABLE_COST_CENTER_ENFORCEMENT": "1"
            if self.settings_bool_vars["ENABLE_COST_CENTER_ENFORCEMENT"].get()
            else "0",
            "OBSERVABILITY_ENABLED": "1" if self.settings_bool_vars["OBSERVABILITY_ENABLED"].get() else "0",
            "API_INTERNAL_ENABLED": "1" if self.settings_bool_vars["API_INTERNAL_ENABLED"].get() else "0",
            "API_INTERNAL_POSTGRES_SHADOW_ENABLED": "1"
            if self.settings_bool_vars["API_INTERNAL_POSTGRES_SHADOW_ENABLED"].get()
            else "0",
            "API_INTERNAL_USE_FOR_PATIENT_READ": "1"
            if self.settings_bool_vars["API_INTERNAL_USE_FOR_PATIENT_READ"].get()
            else "0",
            "API_INTERNAL_USE_FOR_DIAGNOSIS": "1"
            if self.settings_bool_vars["API_INTERNAL_USE_FOR_DIAGNOSIS"].get()
            else "0",
            "API_INTERNAL_USE_FOR_PATIENT_WRITE": "1"
            if self.settings_bool_vars["API_INTERNAL_USE_FOR_PATIENT_WRITE"].get()
            else "0",
        }
        for key, var in self.settings_text_vars.items():
            value = (var.get() or "").strip()
            if key in int_rules:
                try:
                    parsed = int(value or "0")
                except Exception:
                    messagebox.showerror("Setari", f"Valoare invalida pentru {key}: {value}")
                    return
                parsed = max(int_rules[key], parsed)
                payload[key] = str(parsed)
                var.set(str(parsed))
            else:
                payload[key] = value

        for key in ("SIUI_DRG_AUTH_TYPE", "MEDIS_AUTH_TYPE"):
            auth_value = str(payload.get(key, "") or "").strip().lower() or "none"
            if auth_value not in {"none", "bearer", "api_key", "client_credentials"}:
                messagebox.showerror(
                    "Setari",
                    f"Valoare invalida pentru {key}: {auth_value}. Acceptat: none|bearer|api_key|client_credentials",
                )
                return
            payload[key] = auth_value

        currency = str(payload.get("ORG_DEFAULT_CURRENCY", "RON") or "RON").strip().upper() or "RON"
        if not re.fullmatch(r"[A-Z]{3}", currency):
            messagebox.showerror("Setari", "ORG_DEFAULT_CURRENCY trebuie sa fie cod ISO cu 3 litere (ex: RON).")
            return
        payload["ORG_DEFAULT_CURRENCY"] = currency
        self.settings_text_vars["ORG_DEFAULT_CURRENCY"].set(currency)

        fiscal_mmdd = str(payload.get("ORG_FISCAL_YEAR_START_MMDD", "0101") or "0101").strip()
        if not re.fullmatch(r"\d{4}", fiscal_mmdd):
            messagebox.showerror("Setari", "ORG_FISCAL_YEAR_START_MMDD trebuie sa fie in format MMDD (ex: 0101).")
            return
        mm = int(fiscal_mmdd[:2])
        dd = int(fiscal_mmdd[2:])
        if mm < 1 or mm > 12 or dd < 1 or dd > 31:
            messagebox.showerror("Setari", "ORG_FISCAL_YEAR_START_MMDD are valori invalide.")
            return
        payload["ORG_FISCAL_YEAR_START_MMDD"] = fiscal_mmdd

        reset_policy = str(payload.get("DOCNUM_RESET_POLICY_DEFAULT", "yearly") or "yearly").strip().lower() or "yearly"
        if reset_policy not in {"none", "yearly"}:
            messagebox.showerror("Setari", "DOCNUM_RESET_POLICY_DEFAULT accepta doar: none | yearly")
            return
        payload["DOCNUM_RESET_POLICY_DEFAULT"] = reset_policy
        self.settings_text_vars["DOCNUM_RESET_POLICY_DEFAULT"].set(reset_policy)

        try:
            ai_temp = float(payload.get("AI_TEMPERATURE", "0.2") or "0.2")
            ai_temp = max(0.0, min(1.0, ai_temp))
            payload["AI_TEMPERATURE"] = str(ai_temp)
            self.settings_text_vars["AI_TEMPERATURE"].set(str(ai_temp))
        except Exception:
            messagebox.showerror("Setari", "Valoare invalida pentru AI_TEMPERATURE.")
            return

        debounce_float_rules = {
            "DASHBOARD_REFRESH_DEBOUNCE_SECONDS": (0.8, 0.1, 10.0),
            "EXPORT_DEBOUNCE_SECONDS": (0.9, 0.1, 10.0),
            "QUICK_EXPORT_DEBOUNCE_SECONDS": (1.2, 0.1, 15.0),
            "SIUI_DRG_RETRY_BASE_SECONDS": (1.0, 0.1, 60.0),
            "MEDIS_RETRY_BASE_SECONDS": (1.0, 0.1, 60.0),
        }
        for key, (default_v, min_v, max_v) in debounce_float_rules.items():
            try:
                parsed = float(payload.get(key, str(default_v)) or default_v)
            except Exception:
                messagebox.showerror("Setari", f"Valoare invalida pentru {key}: {payload.get(key, '')}")
                return
            parsed = max(min_v, min(max_v, parsed))
            normalized = (f"{parsed:.2f}").rstrip("0").rstrip(".")
            payload[key] = normalized
            if key in self.settings_text_vars:
                self.settings_text_vars[key].set(normalized)

        try:
            shadow_stop = float(payload.get("API_INTERNAL_POSTGRES_SHADOW_STOP_ON_ERROR_RATE", "0.5") or "0.5")
        except Exception:
            messagebox.showerror("Setari", "Valoare invalida pentru API_INTERNAL_POSTGRES_SHADOW_STOP_ON_ERROR_RATE.")
            return
        shadow_stop = max(0.0, min(1.0, shadow_stop))
        payload["API_INTERNAL_POSTGRES_SHADOW_STOP_ON_ERROR_RATE"] = (
            (f"{shadow_stop:.3f}").rstrip("0").rstrip(".") or "0"
        )
        self.settings_text_vars["API_INTERNAL_POSTGRES_SHADOW_STOP_ON_ERROR_RATE"].set(
            payload["API_INTERNAL_POSTGRES_SHADOW_STOP_ON_ERROR_RATE"]
        )

        try:
            obs_ratio = float(payload.get("OBSERVABILITY_SAMPLE_RATIO", "1.0") or "1.0")
        except Exception:
            messagebox.showerror("Setari", "Valoare invalida pentru OBSERVABILITY_SAMPLE_RATIO.")
            return
        obs_ratio = max(0.0, min(1.0, obs_ratio))
        payload["OBSERVABILITY_SAMPLE_RATIO"] = (f"{obs_ratio:.2f}").rstrip("0").rstrip(".") or "0"
        self.settings_text_vars["OBSERVABILITY_SAMPLE_RATIO"].set(payload["OBSERVABILITY_SAMPLE_RATIO"])

        obs_service = str(payload.get("OBSERVABILITY_SERVICE_NAME", "") or "").strip() or "pacienti-ai-desktop"
        payload["OBSERVABILITY_SERVICE_NAME"] = obs_service
        self.settings_text_vars["OBSERVABILITY_SERVICE_NAME"].set(obs_service)

        api_base_url = str(payload.get("API_INTERNAL_BASE_URL", "") or "").strip()
        if api_base_url:
            if not (api_base_url.startswith("http://") or api_base_url.startswith("https://")):
                messagebox.showerror("Setari", "API_INTERNAL_BASE_URL trebuie sa inceapa cu http:// sau https://")
                return
            payload["API_INTERNAL_BASE_URL"] = api_base_url.rstrip("/")
            self.settings_text_vars["API_INTERNAL_BASE_URL"].set(payload["API_INTERNAL_BASE_URL"])

        api_backend = str(payload.get("API_INTERNAL_DB_BACKEND", "sqlite") or "sqlite").strip().lower() or "sqlite"
        if api_backend not in {"sqlite", "postgres"}:
            messagebox.showerror("Setari", "API_INTERNAL_DB_BACKEND accepta doar sqlite | postgres.")
            return
        payload["API_INTERNAL_DB_BACKEND"] = api_backend
        self.settings_text_vars["API_INTERNAL_DB_BACKEND"].set(api_backend)

        selected_model = (payload.get("OPENAI_MODEL", "") or "").strip() or DEFAULT_MODEL
        payload["OPENAI_MODEL"] = selected_model
        self.settings_text_vars["OPENAI_MODEL"].set(selected_model)
        model_options_csv = (payload.get("AI_MODEL_OPTIONS", "") or "").strip()
        model_options = self._parse_csv_options(model_options_csv, DEFAULT_AI_MODEL_OPTIONS)
        if selected_model not in model_options:
            model_options.insert(0, selected_model)
        payload["AI_MODEL_OPTIONS"] = ",".join(model_options)
        self.settings_text_vars["AI_MODEL_OPTIONS"].set(payload["AI_MODEL_OPTIONS"])

        profiles_csv = (payload.get("AI_PROFILE_PRESETS", "") or "").strip()
        profile_presets = self._parse_ai_profile_presets(profiles_csv, DEFAULT_AI_PROFILE_PRESETS)
        if not any((p.get("model") or "").strip() == selected_model for p in profile_presets):
            profile_presets.insert(
                0,
                {
                    "name": "Custom",
                    "model": selected_model,
                    "temperature": payload.get("AI_TEMPERATURE", "0.2"),
                },
            )
        payload["AI_PROFILE_PRESETS"] = self._serialize_ai_profile_presets(profile_presets)
        self.settings_text_vars["AI_PROFILE_PRESETS"].set(payload["AI_PROFILE_PRESETS"])

        try:
            payload["CARE_WARD_CAPACITY_OVERRIDES"] = self._normalize_capacity_overrides(
                payload.get("CARE_WARD_CAPACITY_OVERRIDES", "")
            )
            self.settings_text_vars["CARE_WARD_CAPACITY_OVERRIDES"].set(payload["CARE_WARD_CAPACITY_OVERRIDES"])
        except ValueError as exc:
            messagebox.showerror("Setari", str(exc))
            return

        watch_high = int(payload.get("WATCHLIST_SCORE_HIGH_THRESHOLD", "90") or "90")
        watch_medium = int(payload.get("WATCHLIST_SCORE_MEDIUM_THRESHOLD", "60") or "60")
        max_medium = watch_high - 1 if watch_high > 1 else 1
        if watch_medium > max_medium:
            watch_medium = max_medium
        payload["WATCHLIST_SCORE_HIGH_THRESHOLD"] = str(watch_high)
        payload["WATCHLIST_SCORE_MEDIUM_THRESHOLD"] = str(watch_medium)
        self.settings_text_vars["WATCHLIST_SCORE_HIGH_THRESHOLD"].set(str(watch_high))
        self.settings_text_vars["WATCHLIST_SCORE_MEDIUM_THRESHOLD"].set(str(watch_medium))

        self._refresh_ai_model_combobox_values()
        self._render_ai_profile_buttons()

        self.db.set_settings(payload)
        self._audit(
            "update_app_settings",
            self._audit_details_from_pairs(("keys", ",".join(sorted(payload.keys())))),
        )
        previous_ui_compact = bool(getattr(self, "ui_compact_menus_enabled", True))
        requested_ui_compact = bool(self.settings_bool_vars["UI_COMPACT_MENUS_ENABLED"].get())

        if apply_now:
            self._load_runtime_settings()
            self._schedule_integration_jobs()
            self._refresh_ui_compact_toolbar_status()
            self.refresh_ai_status()
            self._schedule_alert_poll()
            if self.backup_enabled:
                self._schedule_backup_job(delay_seconds=15)
            elif self.backup_job:
                try:
                    self.root.after_cancel(self.backup_job)
                except Exception:
                    pass
                self.backup_job = None
            self.refresh_dashboard()
            if self._has_role("admin", "medic", "receptie"):
                self.refresh_statistics()
            if previous_ui_compact != requested_ui_compact:
                self.settings_hint_var.set(
                    "Setari salvate si aplicate. Modificarea UI compact menus va fi vizibila complet dupa restart aplicatie."
                )
            else:
                self.settings_hint_var.set(
                    "Setari salvate si aplicate in sesiunea curenta. "
                    f"Debounce activ: refresh={self._format_debounce_seconds(self.dashboard_refresh_debounce_seconds)}s, "
                    f"export={self._format_debounce_seconds(self.export_debounce_seconds)}s, "
                    f"rapid={self._format_debounce_seconds(self.quick_export_debounce_seconds)}s."
                )
        else:
            self.settings_hint_var.set("Setari salvate. Vor fi aplicate integral la restart.")

        messagebox.showinfo("Setari", "Setarile au fost salvate.")

    def _settings_export_keys(self) -> List[str]:
        keys = set(self.settings_text_vars.keys())
        keys.update(self.settings_bool_vars.keys())
        keys.update(
            {
                "DASHBOARD_FILTER_DEPARTMENT",
                "DASHBOARD_OPERATIONAL_DATE",
                "PATIENT_STATUS_FILTER",
                "PATIENT_STATUS_DATE",
                "STATS_FILTER_DEPARTMENT",
                "STATS_FILTER_DATE_FROM",
                "STATS_FILTER_DATE_TO",
            }
        )
        return sorted(keys)

    def export_admin_settings_json(self) -> None:
        if not self._require_role("Export setari", "admin"):
            return
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        default_name = f"app_settings_{stamp}.json"
        out_path = filedialog.asksaveasfilename(
            title="Export setari aplicatie",
            initialdir=str(EXPORTS_DIR),
            initialfile=default_name,
            defaultextension=".json",
            filetypes=(("JSON", "*.json"), ("Toate fisierele", "*.*")),
        )
        if not out_path:
            return
        all_settings = self.db.get_all_settings()
        keys = self._settings_export_keys()
        payload = {
            "meta": {
                "exported_at": now_ts(),
                "app": "PacientiAIIndependent",
                "settings_schema_version": SETTINGS_SCHEMA_VERSION,
            },
            "settings": {k: all_settings.get(k, "") for k in keys},
        }
        try:
            Path(out_path).write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
            self._audit(
                "export_app_settings_json",
                self._audit_details_from_pairs(("file", out_path)),
            )
            messagebox.showinfo("Setari", f"Setari exportate:\n{out_path}")
        except Exception as exc:
            messagebox.showerror("Setari", f"Export esuat: {exc}")

    def import_admin_settings_json(self) -> None:
        if not self._require_role("Import setari", "admin"):
            return
        in_path = filedialog.askopenfilename(
            title="Import setari aplicatie",
            initialdir=str(EXPORTS_DIR),
            filetypes=(("JSON", "*.json"), ("Toate fisierele", "*.*")),
        )
        if not in_path:
            return
        try:
            raw = Path(in_path).read_text(encoding="utf-8")
            payload = json.loads(raw)
            meta = payload.get("meta") if isinstance(payload, dict) else None
            schema_version = 1
            if isinstance(meta, dict):
                try:
                    schema_version = int(meta.get("settings_schema_version", 1) or 1)
                except Exception:
                    schema_version = 1

            if schema_version > SETTINGS_SCHEMA_VERSION:
                proceed = messagebox.askyesno(
                    "Schema setari mai noua",
                    (
                        "Fisierul de setari este exportat dintr-o versiune mai noua a aplicatiei.\n"
                        f"Schema fisier: {schema_version}; schema locala: {SETTINGS_SCHEMA_VERSION}.\n\n"
                        "Continui cu import best-effort (doar cheile compatibile)?"
                    ),
                )
                if not proceed:
                    return

            settings = payload.get("settings") if isinstance(payload, dict) else None
            if not isinstance(settings, dict):
                raise ValueError("Fisier JSON invalid: lipseste obiectul 'settings'.")

            allowed = set(self._settings_export_keys())
            normalized = {str(k): str(v) for k, v in settings.items()}
            filtered = {k: v for k, v in normalized.items() if k in allowed}
            ignored = sorted([k for k in normalized.keys() if k not in allowed])
            if not filtered:
                raise ValueError("Nu s-au gasit chei de setari compatibile.")

            self.db.set_settings(filtered)
            self._audit(
                "import_app_settings_json",
                self._audit_details_from_pairs(
                    ("file", in_path),
                    ("imported", len(filtered)),
                    ("ignored", len(ignored)),
                    ("schema", schema_version),
                ),
            )
            self.refresh_settings_form()

            apply_now = messagebox.askyesno(
                "Setari",
                "Import finalizat. Aplic setarile imediat in sesiunea curenta?",
            )
            if apply_now:
                self._load_runtime_settings()
                self.refresh_ai_status()
                self._schedule_alert_poll()
                if self.backup_enabled:
                    self._schedule_backup_job(delay_seconds=15)
                elif self.backup_job:
                    try:
                        self.root.after_cancel(self.backup_job)
                    except Exception:
                        pass
                    self.backup_job = None
                self.settings_hint_var.set("Setari importate si aplicate in sesiunea curenta.")
            else:
                self.settings_hint_var.set("Setari importate. Recomandat restart pentru aplicare completa.")
            details = [
                "Import setari finalizat.",
                f"Chei importate: {len(filtered)}",
                f"Chei ignorate: {len(ignored)}",
            ]
            if ignored:
                preview = ", ".join(ignored[:8])
                suffix = "..." if len(ignored) > 8 else ""
                details.append(f"Ignorate: {preview}{suffix}")
            details_text = "\n".join(details)
            self.last_settings_import_report = details_text
            try:
                self.db.set_setting("LAST_SETTINGS_IMPORT_REPORT", details_text)
            except Exception:
                pass
            messagebox.showinfo("Setari", details_text)
        except Exception as exc:
            messagebox.showerror("Setari", f"Import esuat: {exc}")

    def show_last_settings_import_details(self) -> None:
        if not self._require_role("Detalii import setari", "admin"):
            return
        if not self.last_settings_import_report:
            self.last_settings_import_report = (self.db.get_setting("LAST_SETTINGS_IMPORT_REPORT", "") or "").strip()
        if not self.last_settings_import_report:
            messagebox.showinfo("Setari", "Nu exista inca un import de setari in sesiunea curenta.")
            return
        messagebox.showinfo("Setari", self.last_settings_import_report)

    def clear_last_settings_import_details(self) -> None:
        if not self._require_role("Stergere raport import setari", "admin"):
            return
        confirm = messagebox.askyesno("Setari", "Sterg raportul ultimului import salvat?")
        if not confirm:
            return
        self.last_settings_import_report = ""
        try:
            self.db.set_setting("LAST_SETTINGS_IMPORT_REPORT", "")
        except Exception:
            pass
        self._audit(
            "clear_last_import_report",
            self._audit_details_from_pairs(("key", "LAST_SETTINGS_IMPORT_REPORT")),
        )
        self.settings_hint_var.set("Raportul ultimului import a fost sters.")
        messagebox.showinfo("Setari", "Raportul ultimului import a fost sters.")

