    def _refresh_patient_locality_values(self) -> None:
        if self.patient_address_locality_combo is None or self.patient_address_county_var is None:
            return
        county = self.patient_address_county_var.get().strip()
        localities_set = set(self.patient_address_catalog.get(county, [])) if county else set()
        if county:
            try:
                from_street_catalog = self.db.list_street_catalog_localities(county=county, limit=5000)
                localities_set.update(from_street_catalog)
            except Exception:
                pass
        localities = sorted(localities_set, key=lambda item: item.lower())
        self.patient_address_locality_combo.configure(values=tuple(localities))
        self._refresh_patient_address_value_options()
        self._refresh_patient_street_name_values()
        if self.patient_address_locality_var is None:
            return
        current_locality = self.patient_address_locality_var.get().strip()
        if current_locality and current_locality not in localities:
            self.patient_address_locality_var.set("")

    def _refresh_patient_street_name_values(self) -> None:
        if self.patient_address_street_name_combo is None:
            return
        county = self.patient_address_county_var.get().strip() if self.patient_address_county_var is not None else ""
        locality = self.patient_address_locality_var.get().strip() if self.patient_address_locality_var is not None else ""
        selected_type = (
            _canonical_street_type(self.patient_address_street_type_var.get().strip())
            if self.patient_address_street_type_var is not None
            else ""
        )
        rows = self.db.list_street_catalog_entries(county=county, locality=locality, limit=3000)
        values: List[str] = []
        type_map: Dict[str, str] = {}
        for row in rows:
            street_name = str(row["street_name"] or "").strip()
            if not street_name:
                continue
            st_type = _canonical_street_type(str(row["street_type"] or "").strip())
            if selected_type and not _street_type_matches(selected_type, st_type):
                continue
            values.append(street_name)
            if st_type and street_name not in type_map:
                type_map[street_name] = st_type
        current = self.patient_address_street_name_var.get().strip() if self.patient_address_street_name_var is not None else ""
        if (
            current
            and current not in values
            and self.patient_address_street_name_var is not None
            and not self._patient_form_loading
            and not self._patient_address_syncing
        ):
            self._patient_address_syncing = True
            try:
                self.patient_address_street_name_var.set("")
            finally:
                self._patient_address_syncing = False
        self.patient_street_type_by_name = type_map
        self.patient_address_street_name_combo.configure(values=tuple(values))
        if county and locality and not values:
            self._request_on_demand_street_catalog_sync(county=county, locality=locality)

    def _clear_patient_street_selection(self) -> None:
        self._patient_address_syncing = True
        try:
            if self.patient_address_street_type_var is not None:
                self.patient_address_street_type_var.set("")
            if self.patient_address_street_name_var is not None:
                self.patient_address_street_name_var.set("")
            if self.patient_address_number_var is not None:
                self.patient_address_number_var.set("")
            if self.patient_address_block_var is not None:
                self.patient_address_block_var.set("")
            if self.patient_address_stair_var is not None:
                self.patient_address_stair_var.set("")
            if self.patient_address_floor_var is not None:
                self.patient_address_floor_var.set("")
            if self.patient_address_apartment_var is not None:
                self.patient_address_apartment_var.set("")
            if self.patient_address_intercom_var is not None:
                self.patient_address_intercom_var.set("")
            if self.patient_address_extra_var is not None:
                self.patient_address_extra_var.set("")
        finally:
            self._patient_address_syncing = False

    def _refresh_patient_address_value_options(self) -> None:
        if self.patient_address_value_combo is None:
            return
        county = self.patient_address_county_var.get().strip() if self.patient_address_county_var is not None else ""
        if county:
            localities_set = set(self.patient_address_catalog.get(county, []))
            try:
                localities_set.update(self.db.list_street_catalog_localities(county=county, limit=5000))
            except Exception:
                pass
            options = tuple(
                _compose_structured_address(county, locality, "")
                for locality in sorted(localities_set, key=lambda item: item.lower())
            )
        else:
            options = self.patient_address_all_options
        current_address = self.patient_vars["address"].get().strip() if hasattr(self, "patient_vars") else ""
        if current_address and current_address not in options:
            options = (current_address,) + tuple(options)
        self.patient_address_value_combo.configure(values=options)

    def _compose_patient_address_from_selectors(self) -> str:
        county = self.patient_address_county_var.get().strip() if self.patient_address_county_var is not None else ""
        locality = self.patient_address_locality_var.get().strip() if self.patient_address_locality_var is not None else ""
        details_zone = self.patient_address_details_var.get().strip() if self.patient_address_details_var is not None else ""
        details = _compose_address_details_from_parts(
            street_type=self.patient_address_street_type_var.get().strip() if self.patient_address_street_type_var is not None else "",
            street_name=self.patient_address_street_name_var.get().strip() if self.patient_address_street_name_var is not None else "",
            number=self.patient_address_number_var.get().strip() if self.patient_address_number_var is not None else "",
            block=self.patient_address_block_var.get().strip() if self.patient_address_block_var is not None else "",
            stair=self.patient_address_stair_var.get().strip() if self.patient_address_stair_var is not None else "",
            floor=self.patient_address_floor_var.get().strip() if self.patient_address_floor_var is not None else "",
            apartment=self.patient_address_apartment_var.get().strip() if self.patient_address_apartment_var is not None else "",
            intercom=self.patient_address_intercom_var.get().strip() if self.patient_address_intercom_var is not None else "",
            extra=self.patient_address_extra_var.get().strip() if self.patient_address_extra_var is not None else "",
        )
        if details_zone:
            details = f"zona: {details_zone}, {details}" if details else f"zona: {details_zone}"
        return _compose_structured_address(county, locality, details)

    def _apply_patient_address_selector_values(self) -> None:
        if not hasattr(self, "patient_vars"):
            return
        if self._patient_form_loading or self._patient_address_syncing:
            return
        self.patient_vars["address"].set(self._compose_patient_address_from_selectors())
        self._refresh_patient_address_value_options()

    def _sync_patient_address_selectors_from_value(self, address_value: str) -> None:
        if (
            self.patient_address_county_var is None
            or self.patient_address_locality_var is None
            or self.patient_address_details_var is None
        ):
            return
        parsed = _parse_structured_address(address_value)
        self._patient_address_syncing = True
        try:
            self.patient_address_county_var.set(parsed.get("county", ""))
            self._refresh_patient_locality_values()
            self.patient_address_locality_var.set(parsed.get("locality", ""))
            details_raw = parsed.get("details", "")
            details_zone = ""
            details_rest = details_raw
            zone_match = re.match(r"^\s*zona:\s*([^,]+)\s*(?:,\s*(.*))?$", details_raw, re.IGNORECASE)
            if zone_match:
                details_zone = (zone_match.group(1) or "").strip()
                details_rest = (zone_match.group(2) or "").strip()
            details_parts = _parse_address_details_to_parts(details_rest)
            self.patient_address_details_var.set(details_zone)
            if self.patient_address_street_type_var is not None:
                self.patient_address_street_type_var.set(_canonical_street_type(details_parts.get("street_type", "")))
            if self.patient_address_street_name_var is not None:
                self.patient_address_street_name_var.set(details_parts.get("street_name", ""))
            if self.patient_address_number_var is not None:
                self.patient_address_number_var.set(details_parts.get("number", ""))
            if self.patient_address_block_var is not None:
                self.patient_address_block_var.set(details_parts.get("block", ""))
            if self.patient_address_stair_var is not None:
                self.patient_address_stair_var.set(details_parts.get("stair", ""))
            if self.patient_address_floor_var is not None:
                self.patient_address_floor_var.set(details_parts.get("floor", ""))
            if self.patient_address_apartment_var is not None:
                self.patient_address_apartment_var.set(details_parts.get("apartment", ""))
            if self.patient_address_intercom_var is not None:
                self.patient_address_intercom_var.set(details_parts.get("intercom", ""))
            if self.patient_address_extra_var is not None:
                self.patient_address_extra_var.set(details_parts.get("extra", ""))
            self._refresh_patient_address_value_options()
        finally:
            self._patient_address_syncing = False

    def _on_patient_address_county_changed(self, *_args: Any) -> None:
        if not self._patient_form_loading and not self._patient_address_syncing:
            self._clear_patient_street_selection()
        self._refresh_patient_locality_values()
        self._apply_patient_address_selector_values()

    def _on_patient_address_locality_changed(self, *_args: Any) -> None:
        if not self._patient_form_loading and not self._patient_address_syncing:
            self._clear_patient_street_selection()
        self._refresh_patient_street_name_values()
        self._apply_patient_address_selector_values()

    def _on_patient_address_street_type_changed(self, *_args: Any) -> None:
        if self._patient_form_loading or self._patient_address_syncing:
            return
        self._patient_address_syncing = True
        try:
            if self.patient_address_street_type_var is not None:
                normalized = _canonical_street_type(self.patient_address_street_type_var.get())
                if normalized != self.patient_address_street_type_var.get().strip():
                    self.patient_address_street_type_var.set(normalized)
        finally:
            self._patient_address_syncing = False
        self._refresh_patient_street_name_values()
        self._apply_patient_address_selector_values()

    def _on_patient_address_details_changed(self, *_args: Any) -> None:
        self._apply_patient_address_selector_values()

    def _on_patient_address_value_selected(self, _event: Any = None) -> None:
        if not hasattr(self, "patient_vars"):
            return
        self._sync_patient_address_selectors_from_value(self.patient_vars["address"].get())

    def _on_patient_street_name_selected(self, _event: Any = None) -> None:
        if self.patient_address_street_name_var is None:
            return
        street_name = self.patient_address_street_name_var.get().strip()
        if not street_name:
            return
        if self.patient_address_street_type_var is None:
            return
        from_catalog = _canonical_street_type(str(self.patient_street_type_by_name.get(street_name) or "").strip())
        if from_catalog:
            self.patient_address_street_type_var.set(from_catalog)

    @staticmethod
    def _street_catalog_locality_key(county: str, locality: str) -> str:
        return f"{_normalize_match_text(county)}|{_normalize_match_text(locality)}"

    def _request_on_demand_street_catalog_sync(self, *, county: str, locality: str) -> None:
        county_s = str(county or "").strip()
        locality_s = str(locality or "").strip()
        if not county_s or not locality_s:
            return
        key = self._street_catalog_locality_key(county_s, locality_s)
        if not key:
            return
        if key in self.street_catalog_on_demand_running:
            return
        failed_at = self.street_catalog_on_demand_failed_at.get(key)
        if failed_at and (datetime.now() - failed_at) < timedelta(minutes=5):
            return
        if failed_at:
            self.street_catalog_on_demand_failed_at.pop(key, None)
        self.street_catalog_on_demand_running.add(key)
        thread = threading.Thread(
            target=self._street_catalog_on_demand_worker,
            args=(county_s, locality_s, key),
            daemon=True,
        )
        thread.start()

    def _street_catalog_on_demand_worker(self, county: str, locality: str, key: str) -> None:
        try:
            rows = _fetch_street_catalog_for_locality_from_osm(
                county=county,
                locality=locality,
                timeout_seconds=30,
                max_rows=4000,
            )
            if not rows:
                raise RuntimeError("Nu am gasit strazi pentru localitatea selectata.")
            merged = self.db.merge_street_catalog_entries(rows)
            self.root.after(0, lambda: self._on_street_catalog_on_demand_success(county, locality, key, merged, len(rows)))
        except Exception as exc:
            self.root.after(0, lambda err=str(exc): self._on_street_catalog_on_demand_error(county, locality, key, err))

    def _on_street_catalog_on_demand_success(
        self,
        county: str,
        locality: str,
        key: str,
        merged: int,
        fetched: int,
    ) -> None:
        self.street_catalog_on_demand_running.discard(key)
        self.street_catalog_on_demand_failed_at.pop(key, None)
        self.db.set_settings(
            {
                "STREET_CATALOG_LAST_SYNC_SOURCE": "osm_on_demand",
                "STREET_CATALOG_LAST_SYNC_ROWS": str(max(merged, fetched)),
                "STREET_CATALOG_LAST_SYNC_TS": now_ts(),
            }
        )
        selected_county = self.patient_address_county_var.get().strip() if self.patient_address_county_var is not None else ""
        selected_locality = self.patient_address_locality_var.get().strip() if self.patient_address_locality_var is not None else ""
        if self._street_catalog_locality_key(selected_county, selected_locality) == key:
            self._refresh_patient_locality_values()
            self._refresh_patient_street_name_values()

    def _on_street_catalog_on_demand_error(self, county: str, locality: str, key: str, error_text: str) -> None:
        self.street_catalog_on_demand_running.discard(key)
        self.street_catalog_on_demand_failed_at[key] = datetime.now()

    def _trigger_street_catalog_sync_if_due(self) -> None:
        last_sync_raw = (self.street_catalog_last_sync_ts or "").strip()
        due = True
        if last_sync_raw:
            try:
                last_sync_dt = datetime.strptime(last_sync_raw, "%Y-%m-%d %H:%M:%S")
                due = (datetime.now() - last_sync_dt) >= timedelta(days=max(1, int(self.street_catalog_auto_update_days)))
            except Exception:
                due = True
        if due:
            self.trigger_street_catalog_sync(manual=False)

    def trigger_street_catalog_sync(self, *, manual: bool) -> None:
        if self.street_catalog_sync_running:
            if manual:
                messagebox.showinfo("Nomenclator stradal", "Actualizarea este deja in curs.")
            return
        self.street_catalog_sync_running = True
        if manual:
            messagebox.showinfo(
                "Nomenclator stradal",
                "Actualizare pornita din data.gov.ro. Procesul ruleaza in fundal.",
            )
        thread = threading.Thread(
            target=self._street_catalog_sync_worker,
            args=(manual,),
            daemon=True,
        )
        thread.start()

    def _street_catalog_sync_worker(self, manual: bool) -> None:
        try:
            locality_to_county = _build_locality_to_county_index(self.patient_address_catalog)
            rows, stats = _fetch_street_catalog_from_datagov(
                locality_to_county=locality_to_county,
                timeout_seconds=20,
                max_packages=40,
            )
            inserted = self.db.replace_street_catalog(rows)
            if inserted <= 0:
                raise RuntimeError("Nu am extras intrari valide din sursa externa.")
            stamp = now_ts()
            self.db.set_settings(
                {
                    "STREET_CATALOG_LAST_SYNC_TS": stamp,
                    "STREET_CATALOG_LAST_SYNC_SOURCE": "data.gov.ro",
                    "STREET_CATALOG_LAST_SYNC_ROWS": str(inserted),
                    "STREET_CATALOG_LAST_SYNC_PACKAGES": str(stats.get("packages", 0)),
                }
            )
            self.street_catalog_last_sync_ts = stamp
            self.root.after(0, lambda: self._on_street_catalog_sync_success(inserted, stats, manual))
        except Exception as exc:
            self.root.after(0, lambda err=str(exc): self._on_street_catalog_sync_error(err, manual))

    def _on_street_catalog_sync_success(self, inserted: int, stats: Dict[str, int], manual: bool) -> None:
        self.street_catalog_sync_running = False
        self._refresh_patient_locality_values()
        self._refresh_patient_street_name_values()
        if manual:
            messagebox.showinfo(
                "Nomenclator stradal",
                (
                    "Actualizare finalizata.\n"
                    f"Intrari stocate: {inserted}\n"
                    f"Pachete analizate: {int(stats.get('packages', 0))}\n"
                    f"Resurse parsate: {int(stats.get('resources_parsed', 0))}"
                ),
            )

    def _on_street_catalog_sync_error(self, error_text: str, manual: bool) -> None:
        self.street_catalog_sync_running = False
        if manual:
            messagebox.showerror("Nomenclator stradal", f"Actualizare esuata:\n{error_text}")

    def _icd10_title(self, code: str) -> str:
        normalized = _normalize_icd10_code(code)
        if not normalized:
            return ""
        return str(self.icd10_catalog.get(normalized) or normalized)

    def _refresh_patient_primary_diag_values(self, query: str) -> None:
        if self.patient_primary_diag_combo is None:
            return
        options = _search_icd10_options(self.icd10_catalog, query, limit=120)
        self.patient_primary_diag_combo.configure(values=tuple(options))

    def _refresh_patient_secondary_diag_values(self, query: str) -> None:
        if self.patient_secondary_diag_combo is None:
            return
        options = _search_icd10_options(self.icd10_catalog, query, limit=120)
        self.patient_secondary_diag_combo.configure(values=tuple(options))

    def _sync_patient_secondary_diag_var(self) -> None:
        if not hasattr(self, "patient_vars"):
            return
        serialized = _serialize_icd10_codes_csv(self.patient_secondary_diag_codes)
        self.patient_vars["secondary_diagnoses_icd10"].set(serialized)

    def _refresh_patient_secondary_diag_listbox(self) -> None:
        if self.patient_secondary_diag_listbox is None:
            return
        self.patient_secondary_diag_listbox.delete(0, END)
        for code in self.patient_secondary_diag_codes:
            label = _build_icd10_label(code, self._icd10_title(code))
            self.patient_secondary_diag_listbox.insert(END, label)
        self._sync_patient_secondary_diag_var()
        self._on_patient_diagnosis_values_changed()

    def _on_patient_primary_diag_query_changed(self, _event: Any = None) -> None:
        if self.patient_primary_diag_combo is None:
            return
        self._refresh_patient_primary_diag_values(self.patient_primary_diag_combo.get().strip())

    def _on_patient_primary_diag_selected(self, _event: Any = None) -> None:
        if "primary_diagnosis_icd10" not in self.patient_vars:
            return
        raw = self.patient_vars["primary_diagnosis_icd10"].get().strip()
        code = _extract_icd10_code_from_text(raw)
        if code and code in self.icd10_catalog:
            self.patient_vars["primary_diagnosis_icd10"].set(_build_icd10_label(code, self._icd10_title(code)))
        else:
            self.patient_vars["primary_diagnosis_icd10"].set(code)
        self._on_patient_diagnosis_values_changed()

    def _on_patient_secondary_diag_query_changed(self, _event: Any = None) -> None:
        if self.patient_secondary_diag_combo is None:
            return
        self._refresh_patient_secondary_diag_values(self.patient_secondary_diag_combo.get().strip())

    def add_patient_secondary_diagnosis(self, raw_value: str = "") -> None:
        candidate = raw_value or (self.patient_secondary_diag_combo.get().strip() if self.patient_secondary_diag_combo else "")
        code = _extract_icd10_code_from_text(candidate)
        if not code:
            return
        if self.icd10_catalog and code not in self.icd10_catalog:
            messagebox.showwarning("Diagnostice", f"Cod ICD10 necunoscut: {code}")
            return
        if code in self.patient_secondary_diag_codes:
            return
        self.patient_secondary_diag_codes.append(code)
        self.patient_secondary_diag_codes.sort()
        self._refresh_patient_secondary_diag_listbox()
        if self.patient_secondary_diag_combo is not None:
            self.patient_secondary_diag_combo.set("")

    def _on_patient_secondary_diag_selected(self, _event: Any = None) -> None:
        self.add_patient_secondary_diagnosis()

    def remove_selected_patient_secondary_diagnosis(self) -> None:
        if self.patient_secondary_diag_listbox is None:
            return
        selected = self.patient_secondary_diag_listbox.curselection()
        if not selected:
            return
        idx = int(selected[0])
        if idx < 0 or idx >= len(self.patient_secondary_diag_codes):
            return
        del self.patient_secondary_diag_codes[idx]
        self._refresh_patient_secondary_diag_listbox()

    def clear_patient_secondary_diagnoses(self) -> None:
        self.patient_secondary_diag_codes = []
        self._refresh_patient_secondary_diag_listbox()

    def _on_patient_diagnosis_values_changed(self, *_args: Any) -> None:
        if self._patient_form_loading:
            return
        if self.patient_drg_icm_var is not None:
            self.patient_drg_icm_var.set("ICM/DRG estimat: date modificate, recalculeaza.")

    def _current_patient_drg_icm_estimate(self) -> Dict[str, Any]:
        primary_raw = self.patient_vars.get("primary_diagnosis_icd10").get() if hasattr(self, "patient_vars") else ""
        primary_code = _extract_icd10_code_from_text(primary_raw)
        free_diag = self.patient_vars.get("free_diagnosis_text").get() if hasattr(self, "patient_vars") else ""
        birth_date = self.patient_vars.get("birth_date").get() if hasattr(self, "patient_vars") else ""
        return _estimate_drg_icm(
            primary_code=primary_code,
            secondary_codes=list(self.patient_secondary_diag_codes),
            birth_date=birth_date,
            free_diagnosis_text=free_diag,
        )

    def calculate_patient_drg_icm(self) -> None:
        if self.patient_drg_icm_var is None:
            return

        def _set_local_estimate_with_optional_note(note: str = "") -> None:
            estimate_local = self._current_patient_drg_icm_estimate()
            if not estimate_local.get("ok"):
                self.patient_drg_icm_var.set("ICM/DRG estimat: lipseste diagnosticul principal ICD10.")
                return
            drg_code = str(estimate_local.get("drg_code") or "-")
            icm_value = float(estimate_local.get("icm_estimated") or 0.0)
            severity = str(estimate_local.get("severity") or "none")
            suffix = f" ({note})" if note else ""
            self.patient_drg_icm_var.set(
                f"ICM/DRG estimat (neoficial): {drg_code} | ICM ~ {icm_value:.2f} | severitate {severity}.{suffix}"
            )

        if not self._api_internal_ready_for_diagnosis():
            _set_local_estimate_with_optional_note()
            return

        primary_code = _extract_icd10_code_from_text(self.patient_vars.get("primary_diagnosis_icd10").get() if hasattr(self, "patient_vars") else "")
        if not primary_code:
            _set_local_estimate_with_optional_note()
            return
        free_diag = self.patient_vars.get("free_diagnosis_text").get() if hasattr(self, "patient_vars") else ""
        patient_id = int(self.current_patient_id or 0)
        if patient_id <= 0:
            _set_local_estimate_with_optional_note()
            return
        self.patient_drg_icm_var.set("ICM/DRG estimat: calcul prin API intern in curs...")

        def _worker() -> None:
            estimate_seed = json.dumps(
                {
                    "patient_id": int(patient_id),
                    "primary_icd10": str(primary_code or "").strip().upper(),
                    "secondary_icd10": [str(item or "").strip().upper() for item in self.patient_secondary_diag_codes],
                    "free_text": str(free_diag or "").strip(),
                    "updated_at": str(getattr(self, "current_patient_updated_at", "") or "").strip(),
                },
                ensure_ascii=False,
                sort_keys=True,
            )
            estimate_idem_key = "drg-estimate-" + hashlib.sha256(estimate_seed.encode("utf-8")).hexdigest()[:24]
            try:
                api_est = self.enterprise_api_client.drg_icm_estimate(
                    patient_id=patient_id,
                    primary_icd10=primary_code,
                    secondary_icd10=list(self.patient_secondary_diag_codes),
                    free_text=str(free_diag or ""),
                    idempotency_key=estimate_idem_key,
                )
            except Exception as exc:
                self.enterprise_logger.warning("drg_icm_estimate api failed: %s", str(exc))
                self.root.after(0, lambda: _set_local_estimate_with_optional_note("fallback local"))
                return

            def _apply_api_estimate() -> None:
                drg_code = str(api_est.get("drg_code") or "-")
                icm_value = float(api_est.get("icm_estimated") or 0.0)
                severity = str(api_est.get("severity") or "none")
                self.patient_drg_icm_var.set(
                    f"ICM/DRG estimat (neoficial): {drg_code} | ICM ~ {icm_value:.2f} | severitate {severity}. (via API)"
                )

            self.root.after(0, _apply_api_estimate)

        threading.Thread(target=_worker, daemon=True).start()

    def _collect_patient_diagnosis_context_sections(self) -> Dict[str, str]:
        if self.current_patient_id is None:
            return {}
        patient = self.db.get_patient(self.current_patient_id)
        if not patient:
            return {}
        visits = self._read_patient_visits_api_first(int(self.current_patient_id), limit=20)
        orders = self._read_patient_orders_api_first(int(self.current_patient_id), limit=20)
        investigations = self._read_patient_medis_investigations_api_first(int(self.current_patient_id), limit=20)
        visit_text = "\n".join(
            f"{row.get('visit_date')}: {row.get('reason')} | {row.get('diagnosis')} | {row.get('notes')}"
            for row in visits
        )
        order_text = "\n".join(
            f"{row.get('ordered_at')}: {row.get('order_type')} | {row.get('status')} | {row.get('order_text')}"
            for row in orders
        )
        inv_text = "\n".join(
            f"{row.get('requested_at')}: {row.get('status')} | {row.get('result_summary')} | {row.get('result_payload')}"
            for row in investigations
        )
        return {
            "history": str(patient.get("medical_history") or ""),
            "chronic": str(patient.get("chronic_conditions") or ""),
            "medication": str(patient.get("current_medication") or ""),
            "visits": visit_text,
            "orders": order_text,
            "investigations": inv_text,
            "free_diag": str(self.patient_vars.get("free_diagnosis_text").get() if hasattr(self, "patient_vars") else ""),
        }

    def _set_patient_diagnosis_suggestions(self, rows: List[Dict[str, Any]]) -> None:
        if self.patient_diag_suggestion_tree is None:
            return
        for iid in self.patient_diag_suggestion_tree.get_children():
            self.patient_diag_suggestion_tree.delete(iid)
        self.patient_diag_suggestion_map.clear()
        for idx, row in enumerate(rows, start=1):
            code = _normalize_icd10_code(str(row.get("code") or ""))
            if not code:
                continue
            iid = str(idx)
            title = str(row.get("title") or self._icd10_title(code) or code)
            severity = str(row.get("severity") or "none")
            confidence = float(row.get("confidence") or 0.0)
            evidence = str(row.get("evidence") or row.get("reason") or "")
            self.patient_diag_suggestion_map[iid] = {
                "code": code,
                "title": title,
                "severity": severity,
                "confidence": confidence,
                "evidence": evidence,
            }
            self.patient_diag_suggestion_tree.insert(
                "",
                END,
                iid=iid,
                values=(code, title, severity, f"{confidence:.2f}", evidence),
            )

    def _merge_diagnosis_suggestions_with_ai(
        self,
        baseline: List[Dict[str, Any]],
        ai_rows: List[Dict[str, Any]],
    ) -> List[Dict[str, Any]]:
        merged: Dict[str, Dict[str, Any]] = {
            _normalize_icd10_code(str(item.get("code") or "")): dict(item)
            for item in baseline
            if _normalize_icd10_code(str(item.get("code") or ""))
        }
        for item in ai_rows:
            code = _normalize_icd10_code(str(item.get("code") or ""))
            if not code:
                continue
            current = merged.get(code) or {
                "code": code,
                "title": self._icd10_title(code) or code,
                "severity": _classify_icd_complication_level(code),
                "confidence": 0.0,
                "evidence": "",
            }
            current["confidence"] = max(float(current.get("confidence") or 0.0), float(item.get("confidence") or 0.0))
            reason = str(item.get("reason") or "").strip()
            if reason:
                evidence_old = str(current.get("evidence") or "").strip()
                current["evidence"] = f"{evidence_old}; AI: {reason}" if evidence_old else f"AI: {reason}"
            merged[code] = current
        rows = list(merged.values())
        rows.sort(
            key=lambda item: (
                {"MCC": 0, "CC": 1, "none": 2}.get(str(item.get("severity") or "none"), 3),
                -float(item.get("confidence") or 0.0),
                str(item.get("code") or ""),
            )
        )
        return rows

    def suggest_patient_diagnoses_ai(self) -> None:
        if self.current_patient_id is None:
            messagebox.showwarning("Diagnostice", "Selecteaza un pacient.")
            return
        if self.patient_diag_ai_busy:
            messagebox.showinfo("Diagnostice", "Sugestia este deja in lucru.")
            return

        if self._api_internal_ready_for_diagnosis():
            self.patient_diag_ai_busy = True
            if hasattr(self, "patient_diag_suggest_btn") and self.patient_diag_suggest_btn is not None:
                self.patient_diag_suggest_btn.configure(state="disabled")
            if self.patient_diag_hint_var is not None:
                self.patient_diag_hint_var.set("Generare sugestii prin API intern in curs...")
            patient_id = int(self.current_patient_id or 0)

            def _api_worker() -> None:
                diag_seed = json.dumps(
                    {
                        "patient_id": int(patient_id),
                        "updated_at": str(getattr(self, "current_patient_updated_at", "") or "").strip(),
                    },
                    ensure_ascii=False,
                    sort_keys=True,
                )
                diag_idem_key = "diag-suggest-" + hashlib.sha256(diag_seed.encode("utf-8")).hexdigest()[:24]
                try:
                    rows = self.enterprise_api_client.diagnosis_suggestions(
                        patient_id=patient_id,
                        idempotency_key=diag_idem_key,
                    )
                except Exception as exc:
                    self.enterprise_logger.warning("diagnosis_suggestions api failed: %s", str(exc))
                    self.root.after(0, lambda: self._on_patient_diag_suggestions_ready([], f"{exc}; fallback local"))
                    self.root.after(0, self._run_local_patient_diagnosis_suggestions)
                    return
                self.root.after(0, lambda: self._on_patient_diag_suggestions_ready(rows, ""))

            threading.Thread(target=_api_worker, daemon=True).start()
            return

        self._run_local_patient_diagnosis_suggestions()

    def _run_local_patient_diagnosis_suggestions(self) -> None:
        if self.current_patient_id is None:
            return
        context_sections = self._collect_patient_diagnosis_context_sections()
        existing = [_extract_icd10_code_from_text(self.patient_vars["primary_diagnosis_icd10"].get())]
        existing.extend(self.patient_secondary_diag_codes)
        baseline = _rule_based_diagnosis_suggestions(
            context_sections=context_sections,
            icd10_catalog=self.icd10_catalog,
            existing_codes=existing,
            limit=12,
        )
        if not baseline:
            self._set_patient_diagnosis_suggestions([])
            if self.patient_diag_hint_var is not None:
                self.patient_diag_hint_var.set("Nu exista suficiente indicii documentate pentru sugestii ICD10.")
            return
        self.patient_diag_ai_busy = True
        if hasattr(self, "patient_diag_suggest_btn") and self.patient_diag_suggest_btn is not None:
            self.patient_diag_suggest_btn.configure(state="disabled")
        if self.patient_diag_hint_var is not None:
            self.patient_diag_hint_var.set("Generare sugestii in curs...")

        patient = self.db.get_patient(self.current_patient_id)
        visits = self._read_patient_visits_api_first(int(self.current_patient_id), limit=8)
        context_text = self._build_patient_context(patient, visits) if patient else ""

        def _worker() -> None:
            ai_rows: List[Dict[str, Any]] = []
            ai_error = ""
            try:
                if bool(getattr(self, "ai_enabled", True)) and self._ai_role_allowed() and self.ai.is_available():
                    ai_rows = self.ai.suggest_diagnoses(
                        patient_context=context_text,
                        candidate_suggestions=baseline,
                    )
            except Exception as exc:
                ai_error = str(exc)
            merged = self._merge_diagnosis_suggestions_with_ai(baseline, ai_rows)
            self.root.after(0, lambda: self._on_patient_diag_suggestions_ready(merged, ai_error))

        threading.Thread(target=_worker, daemon=True).start()

    def _on_patient_diag_suggestions_ready(self, rows: List[Dict[str, Any]], error_text: str = "") -> None:
        self.patient_diag_ai_busy = False
        if hasattr(self, "patient_diag_suggest_btn") and self.patient_diag_suggest_btn is not None:
            self.patient_diag_suggest_btn.configure(state="normal")
        self._set_patient_diagnosis_suggestions(rows)
        if self.patient_diag_hint_var is not None:
            if error_text:
                self.patient_diag_hint_var.set(f"Sugestii generate pe reguli locale. AI indisponibil: {error_text}")
            elif rows:
                self.patient_diag_hint_var.set(
                    "Sugestii generate. Verifica documentatia clinica inainte de confirmarea diagnosticului."
                )
            else:
                self.patient_diag_hint_var.set("Nu au fost generate sugestii.")

    def _selected_patient_diag_suggestion(self) -> Optional[Dict[str, Any]]:
        if self.patient_diag_suggestion_tree is None:
            return None
        selected = self.patient_diag_suggestion_tree.selection()
        if not selected:
            return None
        return self.patient_diag_suggestion_map.get(str(selected[0]))

    def apply_selected_suggestion_as_primary(self) -> None:
        item = self._selected_patient_diag_suggestion()
        if not item:
            messagebox.showwarning("Diagnostice", "Selecteaza o sugestie.")
            return
        code = _normalize_icd10_code(str(item.get("code") or ""))
        if not code:
            return
        self.patient_vars["primary_diagnosis_icd10"].set(_build_icd10_label(code, self._icd10_title(code)))
        self.calculate_patient_drg_icm()

    def add_selected_suggestion_as_secondary(self) -> None:
        item = self._selected_patient_diag_suggestion()
        if not item:
            messagebox.showwarning("Diagnostice", "Selecteaza o sugestie.")
            return
        self.add_patient_secondary_diagnosis(str(item.get("code") or ""))
        self.calculate_patient_drg_icm()

    def _set_cnp_feedback(self, message: str, *, is_error: bool = False) -> None:
        if self.cnp_feedback_var is not None:
            self.cnp_feedback_var.set((message or "").strip())
        if self.cnp_feedback_label is not None:
            self.cnp_feedback_label.configure(foreground="#b91c1c" if is_error else "#475569")

    def _on_patient_cnp_changed(self, *_args: Any) -> None:
        if not hasattr(self, "patient_vars") or "cnp" not in self.patient_vars:
            return
        cnp = self.patient_vars["cnp"].get().strip()
        if not cnp:
            self._set_cnp_feedback("")
            return
        derived = _derive_cnp_data(cnp)
        if not derived.get("valid"):
            self._set_cnp_feedback(f"CNP invalid: {derived.get('error') or 'format invalid'}", is_error=True)
            return
        county_label = str(derived.get("county_label") or "Necunoscut")
        county_code = str(derived.get("county_code") or "--")
        birth_date = str(derived.get("birth_date") or "")
        age_years = int(derived.get("age_years") or 0)
        self._set_cnp_feedback(
            f"CNP valid: nascut(a) la {birth_date}, judet {county_label} ({county_code}), varsta ~{age_years} ani."
        )
        if self._patient_form_loading:
            return
        self._apply_cnp_autofill_to_form(derived)

    def _apply_cnp_autofill_to_form(self, derived: Dict[str, Any]) -> None:
        if not derived.get("valid") or not hasattr(self, "patient_vars"):
            return
        if not self.patient_vars["birth_date"].get().strip():
            self.patient_vars["birth_date"].set(str(derived.get("birth_date") or ""))
        gender = str(derived.get("gender") or "").strip()
        if gender and not self.patient_vars["gender"].get().strip():
            self.patient_vars["gender"].set(gender)
        if not self.patient_vars["address"].get().strip():
            county_label = str(derived.get("county_label") or "Necunoscut")
            county_code = str(derived.get("county_code") or "--")
            self.patient_vars["address"].set(f"Judet (din CNP): {county_label} (cod {county_code})")
            self._sync_patient_address_selectors_from_value(self.patient_vars["address"].get())

    def _collect_patient_payload(self) -> Dict[str, str]:
        payload: Dict[str, str] = {k: v.get().strip() for k, v in self.patient_vars.items()}
        primary_code = _extract_icd10_code_from_text(payload.get("primary_diagnosis_icd10", ""))
        payload["primary_diagnosis_icd10"] = primary_code
        if self.patient_secondary_diag_codes:
            payload["secondary_diagnoses_icd10"] = _serialize_icd10_codes_csv(self.patient_secondary_diag_codes)
        else:
            payload["secondary_diagnoses_icd10"] = _serialize_icd10_codes_csv(
                _parse_icd10_codes_csv(payload.get("secondary_diagnoses_icd10", ""))
            )
        payload["free_diagnosis_text"] = str(payload.get("free_diagnosis_text") or "").strip()
        for key, widget in self.patient_text_widgets.items():
            payload[key] = widget.get("1.0", END).strip()
        return payload

    def _validate_patient_payload(self, payload: Dict[str, str]) -> Optional[str]:
        if not payload["first_name"] or not payload["last_name"]:
            return "Prenume si nume sunt obligatorii."

        cnp = payload.get("cnp", "")
        if cnp:
            derived = _derive_cnp_data(cnp)
            if not derived.get("valid"):
                return f"CNP invalid: {derived.get('error') or 'format invalid'}"

        primary_code = _normalize_icd10_code(payload.get("primary_diagnosis_icd10", ""))
        secondary_codes = _parse_icd10_codes_csv(payload.get("secondary_diagnoses_icd10", ""))
        if primary_code and self.icd10_catalog and primary_code not in self.icd10_catalog:
            return f"Diagnostic principal ICD10 invalid: {primary_code}."
        for code in secondary_codes:
            if self.icd10_catalog and code not in self.icd10_catalog:
                return f"Diagnostic secundar ICD10 invalid: {code}."
        if primary_code and primary_code in secondary_codes:
            return "Diagnosticul principal nu poate exista si in lista de diagnostice secundare."
        payload["primary_diagnosis_icd10"] = primary_code
        payload["secondary_diagnoses_icd10"] = _serialize_icd10_codes_csv(secondary_codes)

        if payload.get("birth_date"):
            try:
                datetime.strptime(payload["birth_date"], "%Y-%m-%d")
            except ValueError:
                return "Data nasterii are format invalid. Foloseste YYYY-MM-DD."

        email = payload.get("email", "")
        if email and not re.match(r"^[^@\s]+@[^@\s]+\.[^@\s]+$", email):
            return "Email invalid."

        address = str(payload.get("address") or "").strip()
        if address:
            parsed = _parse_structured_address(address)
            county = str(parsed.get("county") or "").strip()
            locality = str(parsed.get("locality") or "").strip()
            localities_by_county = dict(self.patient_address_catalog)
            if county:
                merged_localities = set(localities_by_county.get(county, []))
                try:
                    merged_localities.update(self.db.list_street_catalog_localities(county=county, limit=5000))
                except Exception:
                    pass
                localities_by_county[county] = sorted(merged_localities, key=lambda item: item.lower())
            streets_map: Dict[str, str] = {}
            if county and locality:
                rows = self.db.list_street_catalog_entries(county=county, locality=locality, limit=5000)
                for row in rows:
                    name = str(row["street_name"] or "").strip().lower()
                    if not name:
                        continue
                    if name in streets_map:
                        continue
                    streets_map[name] = _canonical_street_type(str(row["street_type"] or "").strip())
            address_error = _validate_structured_address_correlation(
                address=address,
                localities_by_county=localities_by_county,
                streets_by_name=streets_map,
            )
            if address_error:
                return address_error

        for field_name, label in (("height_cm", "Inaltime"), ("weight_kg", "Greutate")):
            value = payload.get(field_name, "")
            if not value:
                continue
            normalized = value.replace(",", ".")
            try:
                parsed = float(normalized)
            except ValueError:
                return f"{label} trebuie sa fie numar."
            if parsed <= 0:
                return f"{label} trebuie sa fie mai mare decat 0."
            payload[field_name] = normalized

        return None

    def _patient_payload_to_api_body(self, payload: Dict[str, str]) -> Dict[str, Any]:
        body: Dict[str, Any] = {
            "first_name": str(payload.get("first_name") or "").strip(),
            "last_name": str(payload.get("last_name") or "").strip(),
            "cnp": str(payload.get("cnp") or "").strip(),
            "phone": str(payload.get("phone") or "").strip(),
            "email": str(payload.get("email") or "").strip(),
            "birth_date": str(payload.get("birth_date") or "").strip(),
            "address": str(payload.get("address") or "").strip(),
            "gender": str(payload.get("gender") or "").strip(),
            "occupation": str(payload.get("occupation") or "").strip(),
            "insurance_provider": str(payload.get("insurance_provider") or "").strip(),
            "insurance_id": str(payload.get("insurance_id") or "").strip(),
            "emergency_contact_name": str(payload.get("emergency_contact_name") or "").strip(),
            "emergency_contact_phone": str(payload.get("emergency_contact_phone") or "").strip(),
            "blood_type": str(payload.get("blood_type") or "").strip(),
            "height_cm": str(payload.get("height_cm") or "").strip(),
            "weight_kg": str(payload.get("weight_kg") or "").strip(),
            "medical_history": str(payload.get("medical_history") or "").strip(),
            "allergies": str(payload.get("allergies") or "").strip(),
            "chronic_conditions": str(payload.get("chronic_conditions") or "").strip(),
            "current_medication": str(payload.get("current_medication") or "").strip(),
            "surgeries": str(payload.get("surgeries") or "").strip(),
            "family_history": str(payload.get("family_history") or "").strip(),
            "lifestyle_notes": str(payload.get("lifestyle_notes") or "").strip(),
        }
        body["diagnosis"] = {
            "primary_icd10": str(payload.get("primary_diagnosis_icd10") or "").strip(),
            "secondary_icd10": _parse_icd10_codes_csv(str(payload.get("secondary_diagnoses_icd10") or "")),
            "free_text": str(payload.get("free_diagnosis_text") or "").strip(),
        }
        return body

    def _save_patient_local_db(self, payload: Dict[str, str], *, is_new: bool) -> None:
        if is_new:
            new_id = self.db.create_patient(payload)
            self.current_patient_id = new_id
            row = self.db.get_patient(int(new_id))
            self.current_patient_updated_at = str(row["updated_at"] if row else "")
        else:
            self.db.update_patient(int(self.current_patient_id or 0), payload)
            row = self.db.get_patient(int(self.current_patient_id or 0))
            self.current_patient_updated_at = str(row["updated_at"] if row else "")

    def _save_patient_via_api_if_enabled(self, payload: Dict[str, str], *, is_new: bool) -> Tuple[bool, str]:
        if not self._api_internal_ready_for_patient_write():
            return False, ""
        body = self._patient_payload_to_api_body(payload)
        try:
            if is_new:
                response = self.enterprise_api_client.create_patient(payload=body)
                pid = int(response.get("id") or 0)
                if pid <= 0:
                    raise RuntimeError("API nu a returnat un id valid pentru pacientul creat.")
                self.current_patient_id = pid
            else:
                response = self.enterprise_api_client.patch_patient(
                    patient_id=int(self.current_patient_id or 0),
                    payload=body,
                    expected_updated_at=str(getattr(self, "current_patient_updated_at", "") or "").strip(),
                )
                pid = int(response.get("id") or self.current_patient_id or 0)
                if pid > 0:
                    self.current_patient_id = pid
            self.current_patient_updated_at = str(response.get("updated_at") or "").strip()
            return True, "via API intern"
        except Exception as exc:
            self.enterprise_logger.warning("patient write via api failed: %s", str(exc))
            return False, str(exc)

    def _delete_patient_via_api_if_enabled(
        self,
        patient_id: int,
        *,
        expected_updated_at: str = "",
        idempotency_key: str = "",
    ) -> Tuple[bool, str]:
        if not self._api_internal_ready_for_patient_write():
            return False, ""
        try:
            self.enterprise_api_client.delete_patient(
                patient_id=int(patient_id),
                expected_updated_at=str(expected_updated_at or "").strip(),
                idempotency_key=str(idempotency_key or "").strip(),
            )
            return True, "via API intern"
        except Exception as exc:
            self.enterprise_logger.warning("patient delete via api failed: %s", str(exc))
            return False, str(exc)

    @staticmethod
    def _extract_api_http_status_from_error(error_text: str) -> int:
        raw = str(error_text or "")
        marker = "API HTTP "
        if marker not in raw:
            return 0
        tail = raw.split(marker, 1)[1]
        digits = ""
        for ch in tail:
            if ch.isdigit():
                digits += ch
                continue
            break
        if len(digits) < 3:
            return 0
        try:
            return int(digits)
        except Exception:
            return 0

    def _api_write_should_skip_local_fallback(self, error_text: str) -> bool:
        code = self._extract_api_http_status_from_error(error_text)
        return 400 <= int(code or 0) < 500

