    def save_patient(self) -> None:
        if not self._require_role("Salveaza pacient", "admin", "medic", "receptie"):
            return
        payload = self._collect_patient_payload()
        _apply_cnp_autofill_to_payload(payload)
        for key in ("birth_date", "gender", "address"):
            if not self.patient_vars[key].get().strip() and str(payload.get(key) or "").strip():
                self.patient_vars[key].set(str(payload.get(key) or "").strip())
                if key == "address":
                    self._sync_patient_address_selectors_from_value(str(payload.get("address") or ""))
        validation_error = self._validate_patient_payload(payload)
        if validation_error:
            messagebox.showerror("Date invalide", validation_error)
            return

        is_new = self.current_patient_id is None
        used_api, api_note = self._save_patient_via_api_if_enabled(payload, is_new=is_new)
        if not used_api:
            if self._api_internal_ready_for_patient_write() and "API HTTP 409" in str(api_note or ""):
                messagebox.showerror(
                    "Conflict concurenta",
                    (
                        "Fisa pacientului a fost modificata intre timp pe alta sesiune/statie.\n"
                        "Reincarca pacientul si aplica din nou modificarile."
                    ),
                )
                self.refresh_patients()
                self._focus_patient(self.current_patient_id)
                return
            self._save_patient_local_db(payload, is_new=is_new)
            if api_note:
                self.settings_hint_var.set(f"API pacient indisponibil ({api_note}). S-a folosit fallback local.")

        self._create_patient_snapshot_auto(
            patient_id=self.current_patient_id,
            trigger_action="create_patient" if is_new else "update_patient",
            trigger_source="save_patient",
            trigger_ref_id=f"patient_id:{int(self.current_patient_id or 0)}",
        )
        self._audit_current_patient("create_patient" if is_new else "update_patient", "")
        self.refresh_patients()
        self.refresh_operational_views()
        self._focus_patient(self.current_patient_id)
        self.refresh_patient_history_360()
        if used_api:
            messagebox.showinfo("Succes", "Pacientul a fost salvat (via API intern).")
        else:
            messagebox.showinfo("Succes", "Pacientul a fost salvat.")

    def _focus_patient(self, patient_id: Optional[int]) -> None:
        if not patient_id:
            return
        iid = str(patient_id)
        if self.patient_tree.exists(iid):
            self.patient_tree.selection_set(iid)
            self.patient_tree.focus(iid)
            self.patient_tree.see(iid)
            self.on_patient_select()

    def _load_patient_into_form(self, patient: Dict[str, Any]) -> None:
        self._patient_form_loading = True
        try:
            for key, var in self.patient_vars.items():
                var.set(patient[key] or "")
            primary_code = _normalize_icd10_code(str(patient.get("primary_diagnosis_icd10") or ""))
            if primary_code:
                var_value = _build_icd10_label(primary_code, self._icd10_title(primary_code))
            else:
                var_value = ""
            self.patient_vars["primary_diagnosis_icd10"].set(var_value)
            self.patient_secondary_diag_codes = _parse_icd10_codes_csv(str(patient.get("secondary_diagnoses_icd10") or ""))
            self._refresh_patient_secondary_diag_listbox()
            self._sync_patient_address_selectors_from_value(patient["address"] or "")
            for key, widget in self.patient_text_widgets.items():
                widget.delete("1.0", END)
                widget.insert("1.0", patient[key] or "")
            self._on_patient_cnp_changed()
            self._set_patient_diagnosis_suggestions([])
            self.calculate_patient_drg_icm()
        finally:
            self._patient_form_loading = False

    def delete_current_patient(self) -> None:
        if not self._require_role("Sterge pacient", "admin"):
            return
        if self.current_patient_id is None:
            messagebox.showwarning("Neselectat", "Selecteaza un pacient.")
            return
        confirm = messagebox.askyesno(
            "Confirmare stergere",
            "Stergi pacientul selectat?\nSe vor sterge si consultatiile/conversatiile asociate.",
        )
        if not confirm:
            return
        patient_id = self.current_patient_id
        expected_updated_at = str(getattr(self, "current_patient_updated_at", "") or "").strip()
        idem_seed = f"{int(patient_id)}|{expected_updated_at}|delete_patient"
        delete_idem_key = "delete-patient-" + hashlib.sha256(idem_seed.encode("utf-8")).hexdigest()[:24]
        used_api, api_note = self._delete_patient_via_api_if_enabled(
            int(patient_id),
            expected_updated_at=expected_updated_at,
            idempotency_key=delete_idem_key,
        )
        if not used_api:
            if self._api_internal_ready_for_patient_write() and "API HTTP 409" in str(api_note or ""):
                messagebox.showerror(
                    "Conflict concurenta",
                    (
                        "Fisa pacientului a fost modificata intre timp pe alta sesiune/statie.\n"
                        "Reincarca pacientul inainte de stergere."
                    ),
                )
                self.refresh_patients()
                self._focus_patient(int(patient_id))
                return
            self.db.delete_patient(int(patient_id))
            if api_note:
                self.settings_hint_var.set(f"Stergere pacient via API indisponibila ({api_note}). Fallback local activ.")
        self._audit(
            "delete_patient",
            self._audit_details_from_pairs(("operation", "user_delete")),
            patient_id,
        )
        self.current_patient_id = None
        self.refresh_patients()
        self.refresh_operational_views()
        self.new_patient()

    def add_visit(self) -> None:
        if not self._require_role("Adauga nota clinica", "admin", "medic", "asistent"):
            return
        if self.current_patient_id is None:
            messagebox.showwarning("Fara pacient", "Salveaza sau selecteaza mai intai un pacient.")
            return
        visit_date = self.visit_vars["visit_date"].get().strip() or datetime.now().strftime("%Y-%m-%d")
        try:
            datetime.strptime(visit_date, "%Y-%m-%d")
        except ValueError:
            messagebox.showerror("Data invalida", "Format data acceptat: YYYY-MM-DD.")
            return

        reason = self.visit_vars["reason"].get().strip()
        diagnosis = self.visit_vars["diagnosis"].get().strip()
        treatment = self.visit_vars["treatment"].get().strip()
        notes = self.visit_notes.get("1.0", END).strip()
        idem_seed = json.dumps(
            {
                "patient_id": int(self.current_patient_id),
                "visit_date": visit_date,
                "reason": reason,
                "diagnosis": diagnosis,
                "treatment": treatment,
                "notes": notes,
            },
            ensure_ascii=False,
            sort_keys=True,
        )
        visit_idem_key = "create-visit-" + hashlib.sha256(idem_seed.encode("utf-8")).hexdigest()[:24]
        used_api, api_note, _api_response = self._create_visit_via_api_if_enabled(
            patient_id=int(self.current_patient_id),
            visit_date=visit_date,
            reason=reason,
            diagnosis=diagnosis,
            treatment=treatment,
            notes=notes,
            idempotency_key=visit_idem_key,
        )
        if not used_api:
            if self._api_internal_ready_for_patient_write() and self._api_write_should_skip_local_fallback(api_note):
                messagebox.showerror("Consultatie", str(api_note or "Adaugarea consultatiei a esuat prin API intern."))
                self.refresh_visits()
                return
            self.db.add_visit(self.current_patient_id, visit_date, reason, diagnosis, treatment, notes)
            if api_note:
                self.settings_hint_var.set(f"Adaugare consultatie via API indisponibila ({api_note}). Fallback local activ.")
        self._audit_current_patient("add_note", "")
        self.visit_vars["reason"].set("")
        self.visit_vars["diagnosis"].set("")
        self.visit_vars["treatment"].set("")
        self.visit_notes.delete("1.0", END)
        self.refresh_visits()

    def refresh_visits(self) -> None:
        for iid in self.visit_tree.get_children():
            self.visit_tree.delete(iid)
        self.visit_map.clear()
        if self.current_patient_id is None:
            self._set_visit_details("")
            return

        rows: List[Dict[str, Any]] = []
        api_error = ""
        api_ok = False
        if self._api_internal_ready_for_patient_read():
            try:
                rows = [
                    self._normalize_visit_item_for_ui(row)
                    for row in self.enterprise_api_client.list_visits(
                        patient_id=int(self.current_patient_id),
                        limit=200,
                    )
                ]
                api_ok = True
            except Exception as exc:
                api_error = str(exc)
                self.enterprise_logger.warning("visits via api failed: %s", api_error)
        if not api_ok:
            rows = [
                self._normalize_visit_item_for_ui(dict(row))
                for row in self.db.list_visits(int(self.current_patient_id))
            ]
        if api_error and hasattr(self, "settings_hint_var"):
            self.settings_hint_var.set(f"Citire vizite via API indisponibila ({api_error}). Fallback local activ.")
        for row in rows:
            notes_preview = (row["notes"] or "").replace("\n", " ").strip()
            if len(notes_preview) > 70:
                notes_preview = notes_preview[:67] + "..."
            iid = str(row["id"])
            self.visit_map[iid] = dict(row)
            self.visit_tree.insert(
                "",
                END,
                iid=iid,
                values=(row["visit_date"], row["reason"], row["diagnosis"], row["treatment"], notes_preview),
            )
        self._set_visit_details("")

    def on_visit_select(self, _event: Any = None) -> None:
        selected = self.visit_tree.selection()
        if not selected:
            self._set_visit_details("")
            return
        iid = selected[0]
        visit = self.visit_map.get(iid)
        if not visit:
            self._set_visit_details("")
            return

        details = (
            f"Data: {visit.get('visit_date', '')}\n"
            f"Motiv: {visit.get('reason', '')}\n"
            f"Diagnostic: {visit.get('diagnosis', '')}\n"
            f"Tratament: {visit.get('treatment', '')}\n\n"
            f"Note:\n{visit.get('notes', '')}"
        )
        self._set_visit_details(details)

    def _set_visit_details(self, text: str) -> None:
        self.visit_details.configure(state="normal")
        self.visit_details.delete("1.0", END)
        if text:
            self.visit_details.insert("1.0", text)
        self.visit_details.configure(state="disabled")

    def delete_selected_visit(self) -> None:
        if not self._require_role("Sterge nota clinica", "admin", "medic"):
            return
        selected = self.visit_tree.selection()
        if not selected:
            messagebox.showwarning("Neselectat", "Selecteaza o consultatie.")
            return
        visit_id = int(selected[0])
        if not messagebox.askyesno("Confirmare", "Stergi consultatia selectata?"):
            return
        idem_seed = f"{visit_id}|{int(self.current_patient_id or 0)}|delete_visit"
        delete_idem_key = "delete-visit-" + hashlib.sha256(idem_seed.encode("utf-8")).hexdigest()[:24]
        used_api, api_note, _api_response = self._delete_visit_via_api_if_enabled(
            visit_id=visit_id,
            idempotency_key=delete_idem_key,
        )
        if not used_api:
            if self._api_internal_ready_for_patient_write() and self._api_write_should_skip_local_fallback(api_note):
                messagebox.showerror("Consultatie", str(api_note or "Stergerea consultatiei a esuat prin API intern."))
                self.refresh_visits()
                return
            self.db.delete_visit(visit_id)
            if api_note:
                self.settings_hint_var.set(f"Stergere consultatie via API indisponibila ({api_note}). Fallback local activ.")
        self._audit_current_patient(
            "delete_note",
            self._audit_details_from_pairs(("note", "Stergere nota clinica")),
        )
        self.refresh_visits()

    def create_admission(self) -> None:
        if not self._require_role("Creeaza internare", "admin", "medic", "receptie"):
            return
        if self.current_patient_id is None:
            messagebox.showwarning("Fara pacient", "Selecteaza un pacient.")
            return

        admitted_at = self.admission_vars["admitted_at"].get().strip() or now_ts()
        try:
            datetime.strptime(admitted_at, "%Y-%m-%d %H:%M:%S")
        except ValueError:
            messagebox.showerror("Data invalida", "Format admis la: YYYY-MM-DD HH:MM:SS")
            return

        triage = self.admission_vars["triage_level"].get().strip()
        if triage not in {"1", "2", "3", "4", "5"}:
            messagebox.showerror("Triage invalid", "Triage trebuie intre 1 si 5.")
            return

        payload = {
            "patient_id": str(self.current_patient_id),
            "admission_type": self.admission_vars["admission_type"].get().strip() or "inpatient",
            "triage_level": triage,
            "department": self.admission_vars["department"].get().strip(),
            "ward": self.admission_vars["ward"].get().strip(),
            "bed": self.admission_vars["bed"].get().strip(),
            "attending_clinician": self.admission_vars["attending_clinician"].get().strip(),
            "chief_complaint": self.admission_vars["chief_complaint"].get().strip(),
            "admitted_at": admitted_at,
        }

        if self.db.has_active_bed_conflict(payload["department"], payload["ward"], payload["bed"]):
            messagebox.showerror(
                "Conflict internare",
                "Patul selectat este deja ocupat de o internare activa. Alege alta combinatie sectie/salon/pat.",
            )
            return

        active = self.db.get_active_admission(self.current_patient_id)
        if active:
            proceed = messagebox.askyesno(
                "Internare activa existenta",
                f"Pacientul are deja internare activa ({active['mrn']}). Continui cu o internare noua?",
            )
            if not proceed:
                return

        idem_seed = json.dumps(
            {
                "patient_id": int(self.current_patient_id or 0),
                **payload,
            },
            ensure_ascii=False,
            sort_keys=True,
        )
        create_admission_idem = "create-admission-" + hashlib.sha256(idem_seed.encode("utf-8")).hexdigest()[:24]
        used_api, api_note, api_response = self._create_admission_via_api_if_enabled(
            patient_id=int(self.current_patient_id or 0),
            payload=payload,
            idempotency_key=create_admission_idem,
        )
        if used_api:
            admission_id = int(api_response.get("admission_id") or 0)
            if admission_id <= 0:
                messagebox.showerror("Internare", "API intern nu a returnat un admission_id valid.")
                return
            completed_booking_id = int(api_response.get("completed_booking_id") or 0) or None
        else:
            if self._api_internal_ready_for_patient_write() and self._api_write_should_skip_local_fallback(api_note):
                messagebox.showerror("Internare", str(api_note or "Internare esuata prin API intern."))
                return
            admission_id, completed_booking_id = self.db.create_admission(payload, self.current_user.get("id"))
            if api_note:
                self.settings_hint_var.set(f"Internare via API indisponibila ({api_note}). Fallback local activ.")
        self._audit(
            "create_admission",
            self._audit_details_from_pairs(
                ("admission_id", admission_id),
                ("booking_id", completed_booking_id or "-"),
                ("transition", "scheduled_admission->active" if completed_booking_id else "direct->active"),
            ),
            self.current_patient_id,
        )
        self.admission_vars["admitted_at"].set(now_ts())
        self.admission_vars["chief_complaint"].set("")
        self.refresh_admissions()
        self.refresh_orders()
        self.refresh_vitals()
        self.refresh_bookings()
        self.refresh_operational_views()

    def _selected_admission_id(self) -> Optional[int]:
        selected = self.admission_tree.selection()
        if not selected:
            return None
        try:
            return int(selected[0])
        except Exception:
            return None

