    def _read_patient_visits_api_first(self, patient_id: int, limit: int = 200) -> List[Dict[str, Any]]:
        pid = int(patient_id or 0)
        if pid <= 0:
            return []
        if self._api_internal_ready_for_patient_read():
            try:
                return [
                    self._normalize_visit_item_for_ui(row)
                    for row in self.enterprise_api_client.list_visits(
                        patient_id=pid,
                        limit=max(1, int(limit)),
                    )
                ]
            except Exception as exc:
                self.enterprise_logger.warning("visits api-first fallback local: %s", str(exc))
        return [
            self._normalize_visit_item_for_ui(dict(row))
            for row in self.db.list_visits(pid, limit=max(1, int(limit)))
        ]

