    def create_offer_contract(self) -> None:
        if not self._require_role("Adauga oferta/contract", "admin", "medic", "receptie"):
            return
        if self.current_patient_id is None:
            messagebox.showwarning("Ofertare", "Selecteaza un pacient.")
            return
        admission_id = self._selected_admission_id()
        if not admission_id:
            messagebox.showwarning("Ofertare", "Selecteaza o internare.")
            return
        try:
            base_price = float((self.offer_base_price_var.get() or "0").strip().replace(",", "."))
            discount_amount = float((self.offer_discount_var.get() or "0").strip().replace(",", "."))
        except Exception:
            messagebox.showerror("Ofertare", "Pret baza/discount invalide.")
            return
        final_text = (self.offer_final_price_var.get() or "").strip()
        try:
            final_price = float(final_text.replace(",", ".")) if final_text else None
        except Exception:
            messagebox.showerror("Ofertare", "Pret final invalid.")
            return
        notes = self.offer_notes_box.get("1.0", END).strip()
        doc_type = self.offer_doc_type_var.get()
        package_name = self.offer_package_var.get()
        accommodation_type = self.offer_accommodation_var.get()
        idem_seed = json.dumps(
            {
                "patient_id": int(self.current_patient_id),
                "admission_id": int(admission_id),
                "doc_type": doc_type,
                "package_name": package_name,
                "accommodation_type": accommodation_type,
                "base_price": float(base_price),
                "discount_amount": float(discount_amount),
                "final_price": float(final_price) if final_price is not None else None,
                "status": "draft",
                "notes": notes,
            },
            ensure_ascii=False,
            sort_keys=True,
        )
        offer_idem_key = "create-offer-" + hashlib.sha256(idem_seed.encode("utf-8")).hexdigest()[:24]
        used_api, api_note, api_response = self._create_offer_contract_via_api_if_enabled(
            admission_id=int(admission_id),
            doc_type=doc_type,
            package_name=package_name,
            accommodation_type=accommodation_type,
            base_price=float(base_price),
            discount_amount=float(discount_amount),
            final_price=final_price,
            status="draft",
            notes=notes,
            idempotency_key=offer_idem_key,
        )
        if used_api:
            offer_id = int(api_response.get("offer_id") or 0)
            if offer_id <= 0:
                messagebox.showerror("Ofertare", "API intern nu a returnat offer_id valid.")
                return
        else:
            if self._api_internal_ready_for_patient_write() and self._api_write_should_skip_local_fallback(api_note):
                messagebox.showerror("Ofertare", str(api_note or "Crearea ofertei/contractului a esuat prin API intern."))
                self.refresh_offer_contracts()
                return
            try:
                offer_id = self.db.create_offer_contract(
                    patient_id=self.current_patient_id,
                    admission_id=admission_id,
                    doc_type=doc_type,
                    package_name=package_name,
                    accommodation_type=accommodation_type,
                    base_price=base_price,
                    discount_amount=discount_amount,
                    final_price=final_price,
                    status="draft",
                    notes=notes,
                    user_id=self.current_user.get("id"),
                )
            except ValueError as exc:
                messagebox.showerror("Ofertare", str(exc))
                return
            if api_note:
                self.settings_hint_var.set(
                    f"Creare oferta/contract via API indisponibila ({api_note}). Fallback local activ."
                )
        self._audit_current_patient(
            "create_offer_contract",
            self._audit_details_from_pairs(("offer_id", offer_id), ("admission_id", admission_id)),
        )
        self.offer_final_price_var.set("")
        self.offer_notes_box.delete("1.0", END)
        self.refresh_offer_contracts()

    def update_selected_offer_contract_status(self, status: str) -> None:
        if not self._require_role("Actualizeaza status oferta/contract", "admin", "medic", "receptie"):
            return
        offer_id = self._selected_offer_contract_id()
        if not offer_id:
            messagebox.showwarning("Ofertare", "Selecteaza un document.")
            return
        idem_seed = f"{offer_id}|{status}|offer_status"
        status_idem_key = "offer-status-" + hashlib.sha256(idem_seed.encode("utf-8")).hexdigest()[:24]
        used_api, api_note, _api_response = self._update_offer_contract_status_via_api_if_enabled(
            offer_id=int(offer_id),
            status=str(status or "").strip(),
            idempotency_key=status_idem_key,
        )
        if not used_api:
            if self._api_internal_ready_for_patient_write() and self._api_write_should_skip_local_fallback(api_note):
                messagebox.showerror("Ofertare", str(api_note or "Actualizarea statusului a esuat prin API intern."))
                self.refresh_offer_contracts()
                return
            try:
                self.db.update_offer_contract_status(offer_id, status)
            except ValueError as exc:
                messagebox.showerror("Ofertare", str(exc))
                return
            if api_note:
                self.settings_hint_var.set(
                    f"Update status oferta/contract via API indisponibil ({api_note}). Fallback local activ."
                )
        self._audit_current_patient(
            "update_offer_contract_status",
            self._audit_details_from_pairs(("offer_id", offer_id), ("status", status)),
        )
        self.refresh_offer_contracts()

