    def _build_shadow_backend(self) -> PostgresShadowBackend:
        return PostgresShadowBackend(
            dsn=(os.getenv("PACIENTI_POSTGRES_DSN") or "").strip(),
            connect_timeout_seconds=max(1, int(getattr(self, "api_internal_postgres_connect_timeout_seconds", 2) or 2)),
        )

    def _read_shadow_sync_status_api_first(self) -> Dict[str, Any]:
        if self._api_internal_ready_for_ops_read():
            try:
                return dict(self.enterprise_api_client.get_shadow_sync_status())
            except Exception as exc:
                self.enterprise_logger.warning("shadow sync status via api failed: %s", str(exc))
        local = dict(self.db.get_shadow_sync_status(lookback_hours=24))
        local["shadow_mode_enabled"] = bool(getattr(self, "api_internal_postgres_shadow_enabled", False))
        local["shadow_backlog_pending"] = int(local.get("backlog_pending") or 0)
        local["shadow_last_sync_at"] = str(local.get("last_sync_at") or "")
        local["shadow_error_rate_24h"] = float(local.get("error_rate_24h") or 0.0)
        local["timestamp"] = now_ts()
        return local

