    def process_shadow_sync_now(
        self,
        *,
        show_feedback: bool = True,
        source: str = "manual",
        enforce_role: bool = True,
    ) -> Dict[str, Any]:
        if enforce_role and not self._require_role("Proceseaza shadow sync", "admin"):
            return {"processed": 0, "synced": 0, "retried": 0, "failed": 0}
        if not bool(getattr(self, "api_internal_postgres_shadow_enabled", False)):
            summary_disabled = {
                "processed": 0,
                "synced": 0,
                "retried": 0,
                "failed": 0,
                "auto_stopped": False,
                "pending_after": int((self.db.get_shadow_sync_status(lookback_hours=24) or {}).get("backlog_pending") or 0),
                "error_rate_24h": float((self.db.get_shadow_sync_status(lookback_hours=24) or {}).get("error_rate_24h") or 0.0),
                "last_error": "",
            }
            if show_feedback:
                messagebox.showinfo("Shadow sync", "Shadow mode este dezactivat din Setari.")
            return summary_disabled
        summary: Dict[str, Any] = {}
        if self._api_internal_ready_for_ops_read():
            try:
                summary = dict(
                    self.enterprise_api_client.process_shadow_sync(
                        max_jobs=max(1, int(getattr(self, "api_internal_postgres_shadow_batch_size", 50) or 50))
                    )
                )
            except Exception as exc:
                self.enterprise_logger.warning("shadow sync process via api failed: %s", str(exc))
                summary = {}
        if not summary:
            summary = process_shadow_sync_with_backend(
                db=self.db,
                backend=self._build_shadow_backend(),
                max_jobs=max(1, int(getattr(self, "api_internal_postgres_shadow_batch_size", 50) or 50)),
                max_retries=max(0, int(getattr(self, "api_internal_postgres_shadow_max_retries", 3) or 3)),
                stop_on_error_rate=float(getattr(self, "api_internal_postgres_shadow_stop_on_error_rate", 0.5) or 0.5),
            )
        if source == "manual":
            self._audit(
                "shadow_sync_manual_process",
                self._audit_details_from_pairs(
                    ("processed", summary.get("processed")),
                    ("synced", summary.get("synced")),
                    ("retried", summary.get("retried")),
                    ("failed", summary.get("failed")),
                    ("error_rate_24h", summary.get("error_rate_24h")),
                ),
            )
        if bool(summary.get("auto_stopped", False)):
            self.api_internal_postgres_shadow_enabled = False
            try:
                self.db.set_setting("API_INTERNAL_POSTGRES_SHADOW_ENABLED", "0")
            except Exception:
                pass
            self._audit(
                "shadow_sync_auto_stop",
                self._audit_details_from_pairs(
                    ("error_rate_24h", summary.get("error_rate_24h")),
                    ("threshold", self.api_internal_postgres_shadow_stop_on_error_rate),
                ),
            )
        if show_feedback:
            messagebox.showinfo(
                "Shadow sync",
                (
                    f"Processed: {int(summary.get('processed') or 0)}\n"
                    f"Synced: {int(summary.get('synced') or 0)}\n"
                    f"Retried: {int(summary.get('retried') or 0)}\n"
                    f"Failed: {int(summary.get('failed') or 0)}\n"
                    f"Pending: {int(summary.get('pending_after') or 0)}\n"
                    f"Error rate 24h: {float(summary.get('error_rate_24h') or 0.0):.3f}"
                ),
            )
        if hasattr(self, "settings_hint_var"):
            self.settings_hint_var.set(
                (
                    f"Shadow sync: processed={int(summary.get('processed') or 0)}, "
                    f"pending={int(summary.get('pending_after') or 0)}, "
                    f"error_rate_24h={float(summary.get('error_rate_24h') or 0.0):.3f}"
                )
            )
        return summary

